    51→#[derive(Debug, Error)]
    52→pub enum CpError {
    53→    /// Simple [`io::Error`] wrapper
    54→    #[error("{0}")]
    55→    IoErr(#[from] io::Error),
    56→
    57→    /// Wrapper for [`io::Error`] with path context
    58→    #[error("{1}: {0}")]
    59→    IoErrContext(io::Error, String),
    60→
    61→    /// General copy error
    62→    #[error("{0}")]
    63→    Error(String),
    64→
    65→    /// Represents the state when a non-fatal error has occurred
    66→    /// and not all files were copied.
    67→    #[error("{}", translate!("cp-error-not-all-files-copied"))]
    68→    NotAllFilesCopied,
    69→
    70→    /// Simple [`walkdir::Error`] wrapper
    71→    #[error("{0}")]
    72→    WalkDirErr(#[from] walkdir::Error),
    73→
    74→    /// Simple [`StripPrefixError`] wrapper
    75→    #[error(transparent)]
    76→    StripPrefixError(#[from] StripPrefixError),
    77→
    78→    /// Result of a skipped file
    79→    /// Currently happens when "no" is selected in interactive mode or when
    80→    /// `no-clobber` flag is set and destination is already present.
    81→    /// `exit with error` is used to determine which exit code should be returned.
    82→    #[error("Skipped copying file (exit with error = {0})")]
    83→    Skipped(bool),
    84→
    85→    /// Invalid argument error
    86→    #[error("{0}")]
    87→    InvalidArgument(String),
    88→
    89→    /// All standard options are included as an implementation
    90→    /// path, but those that are not implemented yet should return
    91→    /// a `NotImplemented` error.
    92→    #[error("{}", translate!("cp-error-option-not-implemented", "option" => 0))]
    93→    NotImplemented(String),
    94→
    95→    /// Invalid arguments to backup
    96→    #[error(transparent)]
    97→    Backup(#[from] BackupError),
    98→
    99→    #[error("{}", translate!("cp-error-not-a-directory", "path" => .0.quote()))]
   100→    NotADirectory(PathBuf),
   101→}
