   214→/// Preservation settings for various attributes
   215→///
   216→/// It should be derived from options as follows:
   217→///
   218→///  - if there is a list of attributes to preserve (i.e. `--preserve=ATTR_LIST`) parse that list with [`Attributes::parse_iter`],
   219→///  - if `-p` or `--preserve` is given without arguments, use [`Attributes::DEFAULT`],
   220→///  - if `-a`/`--archive` is passed, use [`Attributes::ALL`],
   221→///  - if `-d` is passed use [`Attributes::LINKS`],
   222→///  - otherwise, use [`Attributes::NONE`].
   223→///
   224→/// For full compatibility with GNU, these options should also combine. We
   225→/// currently only do a best effort imitation of that behavior, because it is
   226→/// difficult to achieve in clap, especially with `--no-preserve`.
   227→#[derive(Debug, PartialEq, Eq, Clone, Copy)]
   228→pub struct Attributes {
   229→    #[cfg(unix)]
   230→    pub ownership: Preserve,
   231→    pub mode: Preserve,
   232→    pub timestamps: Preserve,
   233→    pub context: Preserve,
   234→    pub links: Preserve,
   235→    pub xattr: Preserve,
   236→}
   237→
   238→impl Default for Attributes {
   239→    fn default() -> Self {
   240→        Self::NONE
   241→    }
   242→}
   243→
   244→#[derive(Clone, Copy, Debug, PartialEq, Eq)]
   245→pub enum Preserve {
   246→    // explicit means whether the --no-preserve flag is used or not to distinguish out the default value.
   247→    // e.g. --no-preserve=mode means mode = No { explicit = true }
   248→    No { explicit: bool },
   249→    Yes { required: bool },
   250→}
   251→
   252→impl PartialOrd for Preserve {
   253→    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
   254→        Some(self.cmp(other))
   255→    }
   256→}
   257→
   258→impl Ord for Preserve {
   259→    fn cmp(&self, other: &Self) -> Ordering {
   260→        match (self, other) {
   261→            (Self::No { .. }, Self::No { .. }) => Ordering::Equal,
   262→            (Self::Yes { .. }, Self::No { .. }) => Ordering::Greater,
   263→            (Self::No { .. }, Self::Yes { .. }) => Ordering::Less,
   264→            (
   265→                Self::Yes { required: req_self },
   266→                Self::Yes {
   267→                    required: req_other,
   268→                },
   269→            ) => req_self.cmp(req_other),
   270→        }
   271→    }
   272→}
