   274→/// Options for the `cp` command
   275→///
   276→/// All options are public so that the options can be programmatically
   277→/// constructed by other crates, such as nushell. That means that this struct
   278→/// is part of our public API. It should therefore not be changed without good
   279→/// reason.
   280→///
   281→/// The fields are documented with the arguments that determine their value.
   282→#[allow(dead_code)]
   283→#[derive(Debug, Clone, Eq, PartialEq)]
   284→pub struct Options {
   285→    /// `--attributes-only`
   286→    pub attributes_only: bool,
   287→    /// `--backup[=CONTROL]`, `-b`
   288→    pub backup: BackupMode,
   289→    /// `--copy-contents`
   290→    pub copy_contents: bool,
   291→    /// `-H`
   292→    pub cli_dereference: bool,
   293→    /// Determines the type of copying that should be done
   294→    ///
   295→    /// Set by the following arguments:
   296→    ///  - `-l`, `--link`: [`CopyMode::Link`]
   297→    ///  - `-s`, `--symbolic-link`: [`CopyMode::SymLink`]
   298→    ///  - `-u`, `--update[=WHEN]`: [`CopyMode::Update`]
   299→    ///  - `--attributes-only`: [`CopyMode::AttrOnly`]
   300→    ///  - otherwise: [`CopyMode::Copy`]
   301→    pub copy_mode: CopyMode,
   302→    /// `-L`, `--dereference`
   303→    pub dereference: bool,
   304→    /// `-T`, `--no-target-dir`
   305→    pub no_target_dir: bool,
   306→    /// `-x`, `--one-file-system`
   307→    pub one_file_system: bool,
   308→    /// Specifies what to do with an existing destination
   309→    ///
   310→    /// Set by the following arguments:
   311→    ///  - `-i`, `--interactive`: [`OverwriteMode::Interactive`]
   312→    ///  - `-n`, `--no-clobber`: [`OverwriteMode::NoClobber`]
   313→    ///  - otherwise: [`OverwriteMode::Clobber`]
   314→    ///
   315→    /// The `Interactive` and `Clobber` variants have a [`ClobberMode`] argument,
   316→    /// set by the following arguments:
   317→    ///  - `-f`, `--force`: [`ClobberMode::Force`]
   318→    ///  - `--remove-destination`: [`ClobberMode::RemoveDestination`]
   319→    ///  - otherwise: [`ClobberMode::Standard`]
   320→    pub overwrite: OverwriteMode,
   321→    /// `--parents`
   322→    pub parents: bool,
   323→    /// `--sparse[=WHEN]`
   324→    pub sparse_mode: SparseMode,
   325→    /// `--strip-trailing-slashes`
   326→    pub strip_trailing_slashes: bool,
   327→    /// `--reflink[=WHEN]`
   328→    pub reflink_mode: ReflinkMode,
   329→    /// `--preserve=[=ATTRIBUTE_LIST]` and `--no-preserve=ATTRIBUTE_LIST`
   330→    pub attributes: Attributes,
   331→    /// `-R`, `-r`, `--recursive`
   332→    pub recursive: bool,
   333→    /// `-S`, `--suffix`
   334→    pub backup_suffix: String,
   335→    /// `-t`, `--target-directory`
   336→    pub target_dir: Option<PathBuf>,
   337→    /// `--update[=UPDATE]`
   338→    pub update: UpdateMode,
   339→    /// `--debug`
   340→    pub debug: bool,
   341→    /// `-v`, `--verbose`
   342→    pub verbose: bool,
   343→    /// `-g`, `--progress`
   344→    pub progress_bar: bool,
   345→    /// -Z
   346→    pub set_selinux_context: bool,
   347→    // --context
   348→    pub context: Option<String>,
   349→}
