   514→pub fn uu_app() -> Command {
   515→    const MODE_ARGS: &[&str] = &[
   516→        options::LINK,
   517→        options::REFLINK,
   518→        options::SYMBOLIC_LINK,
   519→        options::ATTRIBUTES_ONLY,
   520→        options::COPY_CONTENTS,
   521→    ];
   522→    Command::new(uucore::util_name())
   523→        .version(uucore::crate_version!())
   524→        .about(translate!("cp-about"))
   525→        .help_template(uucore::localized_help_template(uucore::util_name()))
   526→        .override_usage(format_usage(&translate!("cp-usage")))
   527→        .after_help(format!(
   528→            "{}\n\n{}",
   529→            translate!("cp-after-help"),
   530→            backup_control::BACKUP_CONTROL_LONG_HELP
   531→        ))
   532→        .infer_long_args(true)
   533→        .args_override_self(true)
   534→        .arg(
   535→            Arg::new(options::TARGET_DIRECTORY)
   536→                .short('t')
   537→                .conflicts_with(options::NO_TARGET_DIRECTORY)
   538→                .long(options::TARGET_DIRECTORY)
   539→                .value_name(options::TARGET_DIRECTORY)
   540→                .value_hint(clap::ValueHint::DirPath)
   541→                .value_parser(ValueParser::path_buf())
   542→                .help(translate!("cp-help-target-directory")),
   543→        )
   544→        .arg(
   545→            Arg::new(options::NO_TARGET_DIRECTORY)
   546→                .short('T')
   547→                .long(options::NO_TARGET_DIRECTORY)
   548→                .conflicts_with(options::TARGET_DIRECTORY)
   549→                .help(translate!("cp-help-no-target-directory"))
   550→                .action(ArgAction::SetTrue),
   551→        )
   552→        .arg(
   553→            Arg::new(options::INTERACTIVE)
   554→                .short('i')
   555→                .long(options::INTERACTIVE)
   556→                .overrides_with(options::NO_CLOBBER)
   557→                .help(translate!("cp-help-interactive"))
   558→                .action(ArgAction::SetTrue),
   559→        )
   560→        .arg(
   561→            Arg::new(options::LINK)
   562→                .short('l')
   563→                .long(options::LINK)
   564→                .overrides_with_all(MODE_ARGS)
   565→                .help(translate!("cp-help-link"))
   566→                .action(ArgAction::SetTrue),
   567→        )
   568→        .arg(
   569→            Arg::new(options::NO_CLOBBER)
   570→                .short('n')
   571→                .long(options::NO_CLOBBER)
   572→                .overrides_with(options::INTERACTIVE)
   573→                .help(translate!("cp-help-no-clobber"))
   574→                .action(ArgAction::SetTrue),
   575→        )
   576→        .arg(
   577→            Arg::new(options::RECURSIVE)
   578→                .short('R')
