   782→#[uucore::main]
   783→pub fn uumain(args: impl uucore::Args) -> UResult<()> {
   784→    let matches = uucore::clap_localization::handle_clap_result(uu_app(), args)?;
   785→
   786→    let options = Options::from_matches(&matches)?;
   787→
   788→    if options.overwrite == OverwriteMode::NoClobber && options.backup != BackupMode::None {
   789→        return Err(UUsageError::new(
   790→            EXIT_ERR,
   791→            translate!("cp-error-backup-mutually-exclusive"),
   792→        ));
   793→    }
   794→
   795→    let paths: Vec<PathBuf> = matches
   796→        .get_many::<OsString>(options::PATHS)
   797→        .map(|v| v.map(PathBuf::from).collect())
   798→        .unwrap_or_default();
   799→
   800→    let (sources, target) = parse_path_args(paths, &options)?;
   801→
   802→    if let Err(error) = copy(&sources, &target, &options) {
   803→        match error {
   804→            // Error::NotAllFilesCopied is non-fatal, but the error
   805→            // code should still be EXIT_ERR as does GNU cp
   806→            CpError::NotAllFilesCopied => {}
   807→            // Else we caught a fatal bubbled-up error, log it to stderr
   808→            _ => show_error!("{error}"),
   809→        }
   810→        set_exit_code(EXIT_ERR);
   811→    }
   812→
   813→    Ok(())
   814→}
   815→
   816→impl ClobberMode {
   817→    fn from_matches(matches: &ArgMatches) -> Self {
   818→        if matches.get_flag(options::FORCE) {
   819→            Self::Force
   820→        } else if matches.get_flag(options::REMOVE_DESTINATION) {
   821→            Self::RemoveDestination
   822→        } else {
   823→            Self::Standard
   824→        }
   825→    }
   826→}
   827→
   828→impl OverwriteMode {
   829→    fn from_matches(matches: &ArgMatches) -> Self {
   830→        if matches.get_flag(options::INTERACTIVE) {
   831→            Self::Interactive(ClobberMode::from_matches(matches))
   832→        } else if matches.get_flag(options::NO_CLOBBER) {
   833→            Self::NoClobber
   834→        } else {
   835→            Self::Clobber(ClobberMode::from_matches(matches))
   836→        }
   837→    }
   838→}
   839→
   840→impl CopyMode {
   841→    fn from_matches(matches: &ArgMatches) -> Self {
   842→        if matches.get_flag(options::LINK) {
   843→            Self::Link
   844→        } else if matches.get_flag(options::SYMBOLIC_LINK) {
   845→            Self::SymLink
   846→        } else if matches
   847→            .get_one::<String>(update_control::arguments::OPT_UPDATE)
   848→            .is_some()
   849→            || matches.get_flag(update_control::arguments::OPT_UPDATE_NO_ARG)
   850→        {
   851→            Self::Update
   852→        } else if matches.get_flag(options::ATTRIBUTES_ONLY) {
   853→            if matches.get_flag(options::REMOVE_DESTINATION) {
   854→                Self::Copy
   855→            } else {
   856→                Self::AttrOnly
   857→            }
   858→        } else {
   859→            Self::Copy
   860→        }
   861→    }
   862→}
