   864→impl Attributes {
   865→    pub const ALL: Self = Self {
   866→        #[cfg(unix)]
   867→        ownership: Preserve::Yes { required: true },
   868→        mode: Preserve::Yes { required: true },
   869→        timestamps: Preserve::Yes { required: true },
   870→        context: {
   871→            #[cfg(feature = "feat_selinux")]
   872→            {
   873→                Preserve::Yes { required: false }
   874→            }
   875→            #[cfg(not(feature = "feat_selinux"))]
   876→            {
   877→                Preserve::No { explicit: false }
   878→            }
   879→        },
   880→        links: Preserve::Yes { required: true },
   881→        xattr: Preserve::Yes { required: false },
   882→    };
   883→
   884→    pub const NONE: Self = Self {
   885→        #[cfg(unix)]
   886→        ownership: Preserve::No { explicit: false },
   887→        mode: Preserve::No { explicit: false },
   888→        timestamps: Preserve::No { explicit: false },
   889→        context: Preserve::No { explicit: false },
   890→        links: Preserve::No { explicit: false },
   891→        xattr: Preserve::No { explicit: false },
   892→    };
   893→
   894→    // TODO: ownership is required if the user is root, for non-root users it's not required.
   895→    pub const DEFAULT: Self = Self {
   896→        #[cfg(unix)]
   897→        ownership: Preserve::Yes { required: true },
   898→        mode: Preserve::Yes { required: true },
   899→        timestamps: Preserve::Yes { required: true },
   900→        xattr: Preserve::Yes { required: true },
   901→        ..Self::NONE
   902→    };
   903→
   904→    pub const LINKS: Self = Self {
   905→        links: Preserve::Yes { required: true },
   906→        ..Self::NONE
   907→    };
   908→
   909→    pub fn union(self, other: &Self) -> Self {
   910→        Self {
   911→            #[cfg(unix)]
   912→            ownership: self.ownership.max(other.ownership),
   913→            context: self.context.max(other.context),
   914→            timestamps: self.timestamps.max(other.timestamps),
   915→            mode: self.mode.max(other.mode),
   916→            links: self.links.max(other.links),
   917→            xattr: self.xattr.max(other.xattr),
   918→        }
   919→    }
   920→
   921→    /// Set the field to `Preserve::No { explicit: true }` if the corresponding field
   922→    /// in other is set to `Preserve::Yes { .. }`.
   923→    pub fn diff(self, other: &Self) -> Self {
   924→        fn update_preserve_field(current: Preserve, other: Preserve) -> Preserve {
   925→            if matches!(other, Preserve::Yes { .. }) {
   926→                Preserve::No { explicit: true }
   927→            } else {
   928→                current
   929→            }
   930→        }
   931→        Self {
   932→            #[cfg(unix)]
   933→            ownership: update_preserve_field(self.ownership, other.ownership),
   934→            mode: update_preserve_field(self.mode, other.mode),
   935→            timestamps: update_preserve_field(self.timestamps, other.timestamps),
   936→            context: update_preserve_field(self.context, other.context),
   937→            links: update_preserve_field(self.links, other.links),
   938→            xattr: update_preserve_field(self.xattr, other.xattr),
   939→        }
   940→    }
   941→
   942→    pub fn parse_iter<T>(values: impl Iterator<Item = T>) -> CopyResult<Self>
   943→    where
   944→        T: AsRef<str>,
   945→    {
   946→        let mut new = Self::NONE;
   947→        for value in values {
   948→            new = new.union(&Self::parse_single_string(value.as_ref())?);
   949→        }
   950→        Ok(new)
   951→    }
   952→
   953→    /// Tries to match string containing a parameter to preserve with the corresponding entry in the
   954→    /// Attributes struct.
   955→    fn parse_single_string(value: &str) -> CopyResult<Self> {
   956→        let value = value.to_lowercase();
   957→
   958→        if value == "all" {
   959→            return Ok(Self::ALL);
   960→        }
   961→
   962→        let mut new = Self::NONE;
   963→        let attribute = match value.as_ref() {
   964→            "mode" => &mut new.mode,
   965→            #[cfg(unix)]
   966→            "ownership" => &mut new.ownership,
   967→            "timestamps" => &mut new.timestamps,
   968→            "context" => &mut new.context,
   969→            "link" | "links" => &mut new.links,
   970→            "xattr" => &mut new.xattr,
   971→            _ => {
   972→                return Err(CpError::InvalidArgument(
   973→                    translate!("cp-error-invalid-attribute", "value" => value.quote()),
   974→                ));
   975→            }
   976→        };
   977→
   978→        *attribute = Preserve::Yes { required: true };
   979→
   980→        Ok(new)
   981→    }
   982→}
   983→
   984→impl Options {
   985→    #[allow(clippy::cognitive_complexity)]
   986→    fn from_matches(matches: &ArgMatches) -> CopyResult<Self> {
   987→        let not_implemented_opts = vec![
   988→            #[cfg(not(any(windows, unix)))]
   989→            options::ONE_FILE_SYSTEM,
   990→        ];
   991→
   992→        for not_implemented_opt in not_implemented_opts {
   993→            if matches.contains_id(not_implemented_opt)
   994→                && matches.value_source(not_implemented_opt)
   995→                    == Some(clap::parser::ValueSource::CommandLine)
   996→            {
   997→                return Err(CpError::NotImplemented(not_implemented_opt.to_string()));
   998→            }
   999→        }
  1000→
  1001→        let recursive = matches.get_flag(options::RECURSIVE) || matches.get_flag(options::ARCHIVE);
  1002→
  1003→        let backup_mode = match backup_control::determine_backup_mode(matches) {
  1004→            Err(e) => return Err(CpError::Backup(BackupError(format!("{e}")))),
  1005→            Ok(mode) => mode,
  1006→        };
  1007→        let update_mode = update_control::determine_update_mode(matches);
  1008→
  1009→        if backup_mode != BackupMode::None
  1010→            && matches
  1011→                .get_one::<String>(update_control::arguments::OPT_UPDATE)
  1012→                .is_some_and(|v| v == "none" || v == "none-fail")
  1013→        {
  1014→            return Err(CpError::InvalidArgument(
  1015→                translate!("cp-error-invalid-backup-argument").to_string(),
  1016→            ));
  1017→        }
  1018→
  1019→        let backup_suffix = backup_control::determine_backup_suffix(matches);
  1020→
  1021→        let overwrite = OverwriteMode::from_matches(matches);
  1022→
  1023→        // Parse target directory options
  1024→        let no_target_dir = matches.get_flag(options::NO_TARGET_DIRECTORY);
  1025→        let target_dir = matches
  1026→            .get_one::<PathBuf>(options::TARGET_DIRECTORY)
  1027→            .cloned();
  1028→
  1029→        if let Some(dir) = &target_dir {
  1030→            if !dir.is_dir() {
  1031→                return Err(CpError::NotADirectory(dir.clone()));
  1032→            }
  1033→        }
  1034→        // cp follows POSIX conventions for overriding options such as "-a",
  1035→        // "-d", "--preserve", and "--no-preserve". We can use clap's
  1036→        // override-all behavior to achieve this, but there's a challenge: when
  1037→        // clap overrides an argument, it removes all traces of it from the
  1038→        // match. This poses a problem because flags like "-a" expand to "-dR
  1039→        // --preserve=all", and we only want to override the "--preserve=all"
  1040→        // part. Additionally, we need to handle multiple occurrences of the
  1041→        // same flags. To address this, we create an overriding order from the
  1042→        // matches here.
  1043→        let mut overriding_order: Vec<(usize, &str, Vec<&String>)> = vec![];
  1044→        // We iterate through each overriding option, adding each occurrence of
  1045→        // the option along with its value and index as a tuple, and push it to
  1046→        // `overriding_order`.
  1047→        for option in [
  1048→            options::PRESERVE,
  1049→            options::NO_PRESERVE,
  1050→            options::ARCHIVE,
  1051→            options::PRESERVE_DEFAULT_ATTRIBUTES,
  1052→            options::NO_DEREFERENCE_PRESERVE_LINKS,
  1053→        ] {
  1054→            if let (Ok(Some(val)), Some(index)) = (
  1055→                matches.try_get_one::<bool>(option),
  1056→                // even though it says in the doc that `index_of` would give us
  1057→                // the first index of the argument, when it comes to flag it
  1058→                // gives us the last index where the flag appeared (probably
  1059→                // because it overrides itself). Since it is a flag and it would
  1060→                // have same value across the occurrences we just need the last
  1061→                // index.
  1062→                matches.index_of(option),
  1063→            ) {
  1064→                if *val {
  1065→                    overriding_order.push((index, option, vec![]));
  1066→                }
  1067→            } else if let (Some(occurrences), Some(mut indices)) = (
  1068→                matches.get_occurrences::<String>(option),
  1069→                matches.indices_of(option),
  1070→            ) {
  1071→                occurrences.for_each(|val| {
  1072→                    if let Some(index) = indices.next() {
  1073→                        let val = val.collect::<Vec<&String>>();
  1074→                        // As mentioned in the documentation of the indices_of
  1075→                        // function, it provides the indices of the individual
  1076→                        // values. Therefore, to get the index of the first
  1077→                        // value of the next occurrence in the next iteration,
  1078→                        // we need to advance the indices iterator by the length
  1079→                        // of the current occurrence's values.
  1080→                        for _ in 1..val.len() {
  1081→                            indices.next();
  1082→                        }
  1083→                        overriding_order.push((index, option, val));
  1084→                    }
  1085→                });
  1086→            }
  1087→        }
  1088→        overriding_order.sort_by(|a, b| a.0.cmp(&b.0));
  1089→
  1090→        let mut attributes = Attributes::NONE;
  1091→
  1092→        // Iterate through the `overriding_order` and adjust the attributes accordingly.
  1093→        for (_, option, val) in overriding_order {
  1094→            match option {
  1095→                options::ARCHIVE => {
  1096→                    attributes = Attributes::ALL;
  1097→                }
  1098→                options::PRESERVE_DEFAULT_ATTRIBUTES => {
  1099→                    attributes = attributes.union(&Attributes::DEFAULT);
  1100→                }
  1101→                options::NO_DEREFERENCE_PRESERVE_LINKS => {
  1102→                    attributes = attributes.union(&Attributes::LINKS);
  1103→                }
  1104→                options::PRESERVE => {
  1105→                    attributes = attributes.union(&Attributes::parse_iter(val.into_iter())?);
  1106→                }
  1107→                options::NO_PRESERVE => {
  1108→                    if !val.is_empty() {
  1109→                        attributes = attributes.diff(&Attributes::parse_iter(val.into_iter())?);
  1110→                    }
  1111→                }
  1112→                _ => (),
  1113→            }
  1114→        }
  1115→
  1116→        #[cfg(not(feature = "selinux"))]
  1117→        if let Preserve::Yes { required } = attributes.context {
  1118→            let selinux_disabled_error = CpError::Error(translate!("cp-error-selinux-not-enabled"));
  1119→            if required {
  1120→                return Err(selinux_disabled_error);
  1121→            }
  1122→            show_error_if_needed(&selinux_disabled_error);
  1123→        }
  1124→
  1125→        // Extract the SELinux related flags and options
  1126→        let set_selinux_context = matches.get_flag(options::SELINUX);
  1127→
  1128→        let context = if matches.contains_id(options::CONTEXT) {
  1129→            matches.get_one::<String>(options::CONTEXT).cloned()
  1130→        } else {
  1131→            None
  1132→        };
  1133→
  1134→        let options = Self {
  1135→            attributes_only: matches.get_flag(options::ATTRIBUTES_ONLY),
  1136→            copy_contents: matches.get_flag(options::COPY_CONTENTS),
  1137→            cli_dereference: matches.get_flag(options::CLI_SYMBOLIC_LINKS),
  1138→            copy_mode: CopyMode::from_matches(matches),
  1139→            // No dereference is set with -p, -d and --archive
  1140→            dereference: !(matches.get_flag(options::NO_DEREFERENCE)
  1141→                || matches.get_flag(options::NO_DEREFERENCE_PRESERVE_LINKS)
  1142→                || matches.get_flag(options::ARCHIVE)
  1143→                // cp normally follows the link only when not copying recursively or when
  1144→                // --link (-l) is used
  1145→                || (recursive && CopyMode::from_matches(matches)!= CopyMode::Link ))
  1146→                || matches.get_flag(options::DEREFERENCE),
  1147→            one_file_system: matches.get_flag(options::ONE_FILE_SYSTEM),
  1148→            parents: matches.get_flag(options::PARENTS),
  1149→            update: update_mode,
  1150→            debug: matches.get_flag(options::DEBUG),
  1151→            verbose: matches.get_flag(options::VERBOSE) || matches.get_flag(options::DEBUG),
  1152→            strip_trailing_slashes: matches.get_flag(options::STRIP_TRAILING_SLASHES),
  1153→            reflink_mode: {
  1154→                if let Some(reflink) = matches.get_one::<String>(options::REFLINK) {
  1155→                    match reflink.as_str() {
  1156→                        "always" => ReflinkMode::Always,
  1157→                        "auto" => ReflinkMode::Auto,
  1158→                        "never" => ReflinkMode::Never,
  1159→                        value => {
  1160→                            return Err(CpError::InvalidArgument(
  1161→                                translate!("cp-error-invalid-argument", "arg" => value.quote(), "option" => "reflink"),
  1162→                            ));
  1163→                        }
  1164→                    }
  1165→                } else {
  1166→                    ReflinkMode::default()
  1167→                }
  1168→            },
  1169→            sparse_mode: {
  1170→                if let Some(val) = matches.get_one::<String>(options::SPARSE) {
  1171→                    match val.as_str() {
  1172→                        "always" => SparseMode::Always,
  1173→                        "auto" => SparseMode::Auto,
  1174→                        "never" => SparseMode::Never,
  1175→                        _ => {
  1176→                            return Err(CpError::InvalidArgument(
  1177→                                translate!("cp-error-invalid-argument", "arg" => val, "option" => "sparse"),
  1178→                            ));
  1179→                        }
  1180→                    }
  1181→                } else {
  1182→                    SparseMode::Auto
  1183→                }
  1184→            },
  1185→            backup: backup_mode,
  1186→            backup_suffix,
  1187→            overwrite,
  1188→            no_target_dir,
  1189→            attributes,
  1190→            recursive,
  1191→            target_dir,
  1192→            progress_bar: matches.get_flag(options::PROGRESS_BAR),
  1193→            set_selinux_context: set_selinux_context || context.is_some(),
