  1232→    /// Return [`TargetType`] required for `target`.
  1233→    ///
  1234→    /// Treat target as a dir if we have multiple sources or the target
  1235→    /// exists and already is a directory
  1236→    fn determine(sources: &[PathBuf], target: &Path) -> Self {
  1237→        if sources.len() > 1 || target.is_dir() {
