  1245→/// Returns tuple of (Source paths, Target)
  1246→fn parse_path_args(
  1247→    mut paths: Vec<PathBuf>,
  1248→    options: &Options,
  1249→) -> CopyResult<(Vec<PathBuf>, PathBuf)> {
  1250→    if paths.is_empty() {
  1251→        // No files specified
  1252→        return Err(translate!("cp-error-missing-file-operand").into());
  1253→    } else if paths.len() == 1 && options.target_dir.is_none() {
  1254→        // Only one file specified
  1255→        return Err(translate!("cp-error-missing-destination-operand",
  1256→                       "source" => paths[0].quote())
  1257→        .into());
  1258→    }
  1259→
  1260→    // Return an error if the user requested to copy more than one
  1261→    // file source to a file target
  1262→    if options.no_target_dir && options.target_dir.is_none() && paths.len() > 2 {
  1263→        return Err(translate!("cp-error-extra-operand",
  1264→                              "operand" => paths[2].quote())
  1265→        .into());
  1266→    }
  1267→
  1268→    let target = match options.target_dir {
  1269→        Some(ref target) => {
  1270→            // All path args are sources, and the target dir was
  1271→            // specified separately
  1272→            target.clone()
  1273→        }
  1274→        None => {
  1275→            // If there was no explicit target-dir, then use the last
  1276→            // path_arg
  1277→            paths.pop().unwrap()
  1278→        }
  1279→    };
  1280→
  1281→    if options.strip_trailing_slashes {
  1282→        // clippy::assigning_clones added with Rust 1.78
  1283→        // Rust version = 1.76 on OpenBSD stable/7.5
  1284→        #[cfg_attr(not(target_os = "openbsd"), allow(clippy::assigning_clones))]
  1285→        for source in &mut paths {
  1286→            *source = source.components().as_path().to_owned();
  1287→        }
  1288→    }
  1289→
  1290→    Ok((paths, target))
  1291→}
