  1293→/// When handling errors, we don't always want to show them to the user. This function handles that.
  1294→fn show_error_if_needed(error: &CpError) {
  1295→    match error {
  1296→        // When using --no-clobber, we don't want to show
  1297→        // an error message
  1298→        CpError::NotAllFilesCopied => {
  1299→            // Need to return an error code
  1300→        }
  1301→        CpError::Skipped(_) => {
  1302→            // touch a b && echo "n"|cp -i a b && echo $?
  1303→            // should return an error from GNU 9.2
  1304→        }
  1305→        _ => {
  1306→            show_error!("{error}");
  1307→        }
  1308→    }
  1309→}
