  1311→/// Copy all `sources` to `target`.
  1312→///
  1313→/// Returns an `Err(Error::NotAllFilesCopied)` if at least one non-fatal error
  1314→/// was encountered.
  1315→///
  1316→/// Behavior is determined by the `options` parameter, see [`Options`] for details.
  1317→pub fn copy(sources: &[PathBuf], target: &Path, options: &Options) -> CopyResult<()> {
  1318→    let target_type = TargetType::determine(sources, target);
  1319→    verify_target_type(target, &target_type)?;
  1320→
  1321→    let mut non_fatal_errors = false;
  1322→    let mut seen_sources = HashSet::with_capacity(sources.len());
  1323→    let mut symlinked_files = HashSet::new();
  1324→
  1325→    // to remember the copied files for further usage.
  1326→    // the FileInformation implemented the Hash trait by using
  1327→    // 1. inode number
  1328→    // 2. device number
  1329→    // the combination of a file's inode number and device number is unique throughout all the file systems.
  1330→    //
  1331→    // key is the source file's information and the value is the destination filepath.
  1332→    let mut copied_files: HashMap<FileInformation, PathBuf> = HashMap::with_capacity(sources.len());
  1333→    // remember the copied destinations for further usage.
  1334→    // we can't use copied_files as it is because the key is the source file's information.
  1335→    let mut copied_destinations: HashSet<PathBuf> = HashSet::with_capacity(sources.len());
  1336→    let mut created_parent_dirs: HashSet<PathBuf> = HashSet::new();
  1337→
  1338→    let progress_bar = if options.progress_bar {
  1339→        let pb = ProgressBar::new(disk_usage(sources, options.recursive)?)
  1340→            .with_style(
  1341→                ProgressStyle::with_template(
  1342→                    "{msg}: [{elapsed_precise}] {wide_bar} {bytes:>7}/{total_bytes:7}",
  1343→                )
  1344→                .unwrap(),
  1345→            )
  1346→            .with_message(uucore::util_name());
  1347→        pb.tick();
  1348→        Some(pb)
  1349→    } else {
  1350→        None
  1351→    };
  1352→
  1353→    for source in sources {
  1354→        let normalized_source = normalize_path(source);
  1355→        if options.backup == BackupMode::None && seen_sources.contains(&normalized_source) {
  1356→            let file_type = if source.symlink_metadata()?.file_type().is_dir() {
  1357→                "directory"
  1358→            } else {
  1359→                "file"
  1360→            };
  1361→            let msg = translate!("cp-warning-source-specified-more-than-once", "file_type" => file_type, "source" => source.quote());
  1362→            show_warning!("{msg}");
  1363→        } else {
  1364→            let dest = construct_dest_path(source, target, target_type, options)
  1365→                .unwrap_or_else(|_| target.to_path_buf());
  1366→
  1367→            if fs::metadata(&dest).is_ok()
  1368→                && !fs::symlink_metadata(&dest)?.file_type().is_symlink()
  1369→                // if both `source` and `dest` are symlinks, it should be considered as an overwrite.
  1370→                || fs::metadata(source).is_ok()
  1371→                    && fs::symlink_metadata(source)?.file_type().is_symlink()
  1372→                || matches!(options.copy_mode, CopyMode::SymLink)
  1373→            {
  1374→                // There is already a file and it isn't a symlink (managed in a different place)
  1375→                if copied_destinations.contains(&dest) && options.backup != BackupMode::Numbered {
  1376→                    // If the target was already created in this cp call, check if it's a directory.
  1377→                    // Directories should be merged (GNU cp behavior), but files should not be overwritten.
  1378→                    let dest_is_dir = fs::metadata(&dest).is_ok_and(|m| m.is_dir());
  1379→                    let source_is_dir = fs::metadata(source).is_ok_and(|m| m.is_dir());
  1380→
  1381→                    // Only prevent overwriting if both source and dest are files (not directories)
  1382→                    // Directories should be merged, which is handled by copy_directory
  1383→                    if !dest_is_dir || !source_is_dir {
  1384→                        // If the target file was already created in this cp call, do not overwrite
  1385→                        return Err(CpError::Error(
  1386→                            translate!("cp-error-will-not-overwrite-just-created", "dest" => dest.quote(), "source" => source.quote()),
  1387→                        ));
  1388→                    }
  1389→                }
  1390→            }
  1391→
  1392→            if let Err(error) = copy_source(
  1393→                progress_bar.as_ref(),
  1394→                source,
  1395→                target,
  1396→                target_type,
  1397→                options,
  1398→                &mut symlinked_files,
  1399→                &copied_destinations,
  1400→                &mut copied_files,
  1401→                &mut created_parent_dirs,
  1402→            ) {
  1403→                show_error_if_needed(&error);
  1404→                if !matches!(error, CpError::Skipped(false)) {
  1405→                    non_fatal_errors = true;
  1406→                }
  1407→            } else {
  1408→                copied_destinations.insert(dest.clone());
  1409→            }
  1410→        }
  1411→        seen_sources.insert(normalized_source);
  1412→    }
  1413→
  1414→    if let Some(pb) = progress_bar {
  1415→        pb.finish();
  1416→    }
  1417→
  1418→    if non_fatal_errors {
  1419→        Err(CpError::NotAllFilesCopied)
  1420→    } else {
  1421→        Ok(())
  1422→    }
  1423→}
  1424→
  1425→fn construct_dest_path(
  1426→    source_path: &Path,
  1427→    target: &Path,
  1428→    target_type: TargetType,
  1429→    options: &Options,
  1430→) -> CopyResult<PathBuf> {
  1431→    if options.no_target_dir && target.is_dir() {
  1432→        return Err(
  1433→            translate!("cp-error-cannot-overwrite-directory-with-non-directory",
  1434→                              "dir" => target.quote())
  1435→            .into(),
  1436→        );
  1437→    }
  1438→
  1439→    if options.parents && !target.is_dir() {
  1440→        return Err(translate!("cp-error-with-parents-dest-must-be-dir").into());
  1441→    }
  1442→
  1443→    Ok(match target_type {
  1444→        TargetType::Directory => {
  1445→            let root = if options.parents {
  1446→                if source_path.has_root() && cfg!(unix) {
  1447→                    Path::new("/")
  1448→                } else {
  1449→                    Path::new("")
  1450→                }
  1451→            } else {
  1452→                if source_path == Path::new(".") && target.is_dir() {
  1453→                    // Special case: when copying current directory (.) to an existing directory,
  1454→                    // return the target path directly instead of trying to construct a path
  1455→                    // relative to the source's parent. This ensures we copy the contents of
  1456→                    // the current directory into the target directory, not create a subdirectory.
  1457→                    return Ok(target.to_path_buf());
  1458→                }
  1459→                source_path.parent().unwrap_or(source_path)
  1460→            };
  1461→            localize_to_target(root, source_path, target)?
  1462→        }
  1463→        TargetType::File => target.to_path_buf(),
  1464→    })
  1465→}
  1466→#[allow(clippy::too_many_arguments)]
  1467→fn copy_source(
  1468→    progress_bar: Option<&ProgressBar>,
  1469→    source: &Path,
  1470→    target: &Path,
  1471→    target_type: TargetType,
  1472→    options: &Options,
  1473→    symlinked_files: &mut HashSet<FileInformation>,
  1474→    copied_destinations: &HashSet<PathBuf>,
  1475→    copied_files: &mut HashMap<FileInformation, PathBuf>,
  1476→    created_parent_dirs: &mut HashSet<PathBuf>,
  1477→) -> CopyResult<()> {
  1478→    let source_path = Path::new(&source);
  1479→    if source_path.is_dir() && (options.dereference || !source_path.is_symlink()) {
  1480→        // Copy as directory
  1481→        copy_directory(
  1482→            progress_bar,
  1483→            source,
  1484→            target,
  1485→            options,
  1486→            symlinked_files,
  1487→            copied_destinations,
  1488→            copied_files,
  1489→            created_parent_dirs,
  1490→            true,
  1491→        )
  1492→    } else {
  1493→        // Copy as file
  1494→        let dest = construct_dest_path(source_path, target, target_type, options)?;
  1495→        let res = copy_file(
  1496→            progress_bar,
  1497→            source_path,
  1498→            dest.as_path(),
  1499→            options,
  1500→            symlinked_files,
  1501→            copied_destinations,
  1502→            copied_files,
  1503→            created_parent_dirs,
  1504→            true,
  1505→        );
  1506→        if options.parents {
  1507→            for (x, y) in aligned_ancestors(source, dest.as_path()) {
  1508→                if let Ok(src) = canonicalize(x, MissingHandling::Normal, ResolveMode::Physical) {
  1509→                    copy_attributes(&src, y, &options.attributes)?;
  1510→                }
  1511→            }
  1512→        }
  1513→        res
  1514→    }
  1515→}
