  1517→/// If `path` does not have `S_IWUSR` set, returns a tuple of the file's
  1518→/// mode in octal (index 0) and human-readable (index 1) formats.
  1519→///
  1520→/// If the destination of a copy operation is a file that is not writeable to
  1521→/// the owner (bit `S_IWUSR`), extra information needs to be added to the
  1522→/// interactive mode prompt: the mode (permissions) of the file in octal and
  1523→/// human-readable format.
  1524→// TODO
  1525→// The destination metadata can be read multiple times in the course of a single execution of `cp`.
  1526→// This fix adds yet another metadata read.
  1527→// Should this metadata be read once and then reused throughout the execution?
  1528→// https://github.com/uutils/coreutils/issues/6658
  1529→#[allow(clippy::if_not_else)]
  1530→fn file_mode_for_interactive_overwrite(
  1531→    #[cfg_attr(not(unix), allow(unused_variables))] path: &Path,
  1532→) -> Option<(String, String)> {
  1533→    // Retain outer braces to ensure only one branch is included
  1534→    {
  1535→        #[cfg(unix)]
  1536→        {
  1537→            use libc::{S_IWUSR, mode_t};
  1538→            use std::os::unix::prelude::MetadataExt;
  1539→
  1540→            match path.metadata() {
  1541→                Ok(me) => {
  1542→                    // Cast is necessary on some platforms
  1543→                    let mode: mode_t = me.mode() as mode_t;
  1544→
  1545→                    // It looks like this extra information is added to the prompt iff the file's user write bit is 0
  1546→                    //  write permission, owner
  1547→                    if uucore::has!(mode, S_IWUSR) {
  1548→                        None
  1549→                    } else {
  1550→                        // Discard leading digits
  1551→                        let mode_without_leading_digits = mode & 0o7777;
  1552→
  1553→                        Some((
  1554→                            format!("{mode_without_leading_digits:04o}"),
  1555→                            uucore::fs::display_permissions_unix(mode, false),
  1556→                        ))
  1557→                    }
  1558→                }
  1559→                // TODO: How should failure to read the metadata be handled? Ignoring for now.
  1560→                Err(_) => None,
  1561→            }
  1562→        }
  1563→
  1564→        #[cfg(not(unix))]
  1565→        {
  1566→            None
  1567→        }
  1568→    }
  1569→}
