  1571→impl OverwriteMode {
  1572→    fn verify(&self, path: &Path, debug: bool) -> CopyResult<()> {
  1573→        match *self {
  1574→            Self::NoClobber => {
  1575→                if debug {
  1576→                    println!("{}", translate!("cp-debug-skipped", "path" => path.quote()));
  1577→                }
  1578→                Err(CpError::Skipped(false))
  1579→            }
  1580→            Self::Interactive(_) => {
  1581→                let prompt_yes_result = if let Some((octal, human_readable)) =
  1582→                    file_mode_for_interactive_overwrite(path)
  1583→                {
  1584→                    let prompt_msg =
  1585→                        translate!("cp-prompt-overwrite-with-mode", "path" => path.quote());
  1586→                    prompt_yes!("{prompt_msg} {octal} ({human_readable})?")
  1587→                } else {
  1588→                    let prompt_msg = translate!("cp-prompt-overwrite", "path" => path.quote());
  1589→                    prompt_yes!("{prompt_msg}")
  1590→                };
  1591→
  1592→                if prompt_yes_result {
  1593→                    Ok(())
  1594→                } else {
  1595→                    Err(CpError::Skipped(true))
  1596→                }
  1597→            }
  1598→            Self::Clobber(_) => Ok(()),
  1599→        }
  1600→    }
  1601→}
