  1603→/// Handles errors for attributes preservation. If the attribute is not required, and
  1604→/// errored, tries to show error (see `show_error_if_needed` for additional behavior details).
  1605→/// If it's required, then the error is thrown.
  1606→fn handle_preserve<F: Fn() -> CopyResult<()>>(p: &Preserve, f: F) -> CopyResult<()> {
  1607→    match p {
  1608→        Preserve::No { .. } => {}
  1609→        Preserve::Yes { required } => {
  1610→            let result = f();
  1611→            if *required {
  1612→                result?;
  1613→            } else if let Err(error) = result {
  1614→                show_error_if_needed(&error);
  1615→            }
  1616→        }
  1617→    }
  1618→    Ok(())
  1619→}
