  1621→/// Copies extended attributes (xattrs) from `source` to `dest`, ensuring that `dest` is temporarily
  1622→/// user-writable if needed and restoring its original permissions afterward. This avoids "Operation
  1623→/// not permitted" errors on read-only files. Returns an error if permission or metadata operations fail,
  1624→/// or if xattr copying fails.
  1625→#[cfg(all(unix, not(target_os = "android")))]
  1626→fn copy_extended_attrs(source: &Path, dest: &Path) -> CopyResult<()> {
  1627→    let metadata = fs::symlink_metadata(dest)?;
  1628→
  1629→    // Check if the destination file is currently read-only for the user.
  1630→    let mut perms = metadata.permissions();
  1631→    let was_readonly = perms.readonly();
  1632→
  1633→    // Temporarily grant user write if it was read-only.
  1634→    if was_readonly {
  1635→        #[allow(clippy::permissions_set_readonly_false)]
  1636→        perms.set_readonly(false);
  1637→        fs::set_permissions(dest, perms)?;
  1638→    }
  1639→
  1640→    // Perform the xattr copy and capture any potential error,
  1641→    // so we can restore permissions before returning.
  1642→    let copy_xattrs_result = copy_xattrs(source, dest);
  1643→
  1644→    // Restore read-only if we changed it.
  1645→    if was_readonly {
  1646→        let mut revert_perms = fs::symlink_metadata(dest)?.permissions();
  1647→        revert_perms.set_readonly(true);
  1648→        fs::set_permissions(dest, revert_perms)?;
  1649→    }
  1650→
  1651→    // If copying xattrs failed, propagate that error now.
  1652→    copy_xattrs_result?;
  1653→
  1654→    Ok(())
  1655→}
  1656→
  1657→/// Copy the specified attributes from one path to another.
  1658→pub(crate) fn copy_attributes(
  1659→    source: &Path,
  1660→    dest: &Path,
  1661→    attributes: &Attributes,
  1662→) -> CopyResult<()> {
  1663→    let context = &*format!("{} -> {}", source.quote(), dest.quote());
  1664→    let source_metadata =
  1665→        fs::symlink_metadata(source).map_err(|e| CpError::IoErrContext(e, context.to_owned()))?;
  1666→
  1667→    // Ownership must be changed first to avoid interfering with mode change.
  1668→    #[cfg(unix)]
  1669→    handle_preserve(&attributes.ownership, || -> CopyResult<()> {
  1670→        use std::os::unix::prelude::MetadataExt;
  1671→        use uucore::perms::Verbosity;
  1672→        use uucore::perms::VerbosityLevel;
  1673→        use uucore::perms::wrap_chown;
  1674→
  1675→        let dest_uid = source_metadata.uid();
  1676→        let dest_gid = source_metadata.gid();
  1677→        let meta = &dest
  1678→            .symlink_metadata()
  1679→            .map_err(|e| CpError::IoErrContext(e, context.to_owned()))?;
  1680→
  1681→        let try_chown = {
  1682→            |uid| {
  1683→                wrap_chown(
  1684→                    dest,
  1685→                    meta,
  1686→                    uid,
  1687→                    Some(dest_gid),
  1688→                    false,
  1689→                    Verbosity {
  1690→                        groups_only: false,
  1691→                        level: VerbosityLevel::Silent,
  1692→                    },
  1693→                )
  1694→            }
  1695→        };
  1696→        // gnu compatibility: cp doesn't report an error if it fails to set the ownership,
  1697→        // and will fall back to changing only the gid if possible.
  1698→        if try_chown(Some(dest_uid)).is_err() {
  1699→            let _ = try_chown(None);
  1700→        }
  1701→        Ok(())
  1702→    })?;
  1703→
  1704→    handle_preserve(&attributes.mode, || -> CopyResult<()> {
  1705→        // The `chmod()` system call that underlies the
  1706→        // `fs::set_permissions()` call is unable to change the
  1707→        // permissions of a symbolic link. In that case, we just
  1708→        // do nothing, since every symbolic link has the same
  1709→        // permissions.
  1710→        if !dest.is_symlink() {
  1711→            fs::set_permissions(dest, source_metadata.permissions())
  1712→                .map_err(|e| CpError::IoErrContext(e, context.to_owned()))?;
  1713→            // FIXME: Implement this for windows as well
  1714→            #[cfg(feature = "feat_acl")]
  1715→            exacl::getfacl(source, None)
  1716→                .and_then(|acl| exacl::setfacl(&[dest], &acl, None))
  1717→                .map_err(|err| CpError::Error(err.to_string()))?;
  1718→        }
  1719→
  1720→        Ok(())
  1721→    })?;
  1722→
  1723→    handle_preserve(&attributes.timestamps, || -> CopyResult<()> {
  1724→        let atime = FileTime::from_last_access_time(&source_metadata);
  1725→        let mtime = FileTime::from_last_modification_time(&source_metadata);
  1726→        if dest.is_symlink() {
  1727→            filetime::set_symlink_file_times(dest, atime, mtime)?;
  1728→        } else {
  1729→            filetime::set_file_times(dest, atime, mtime)?;
  1730→        }
  1731→
  1732→        Ok(())
  1733→    })?;
  1734→
  1735→    #[cfg(feature = "selinux")]
  1736→    handle_preserve(&attributes.context, || -> CopyResult<()> {
  1737→        // Get the source context and apply it to the destination
  1738→        if let Ok(context) = selinux::SecurityContext::of_path(source, false, false) {
  1739→            if let Some(context) = context {
  1740→                if let Err(e) = context.set_for_path(dest, false, false) {
  1741→                    return Err(CpError::Error(
  1742→                        translate!("cp-error-selinux-set-context", "path" => dest.display(), "error" => e),
  1743→                    ));
  1744→                }
  1745→            }
  1746→        } else {
  1747→            return Err(CpError::Error(
  1748→                translate!("cp-error-selinux-get-context", "path" => source.display()),
  1749→            ));
  1750→        }
  1751→        Ok(())
  1752→    })?;
  1753→
  1754→    handle_preserve(&attributes.xattr, || -> CopyResult<()> {
  1755→        #[cfg(all(unix, not(target_os = "android")))]
  1756→        {
  1757→            copy_extended_attrs(source, dest)?;
  1758→        }
  1759→        #[cfg(not(all(unix, not(target_os = "android"))))]
  1760→        {
  1761→            // The documentation for GNU cp states:
  1762→            //
  1763→            // > Try to preserve SELinux security context and
  1764→            // > extended attributes (xattr), but ignore any failure
  1765→            // > to do that and print no corresponding diagnostic.
  1766→            //
  1767→            // so we simply do nothing here.
  1768→            //
  1769→            // TODO Silently ignore failures in the `#[cfg(unix)]`
  1770→            // block instead of terminating immediately on errors.
  1771→        }
  1772→
  1773→        Ok(())
  1774→    })?;
  1775→
  1776→    Ok(())
  1777→}
  1778→
  1779→fn symlink_file(
  1780→    source: &Path,
  1781→    dest: &Path,
  1782→    symlinked_files: &mut HashSet<FileInformation>,
  1783→) -> CopyResult<()> {
  1784→    #[cfg(not(windows))]
  1785→    {
  1786→        std::os::unix::fs::symlink(source, dest).map_err(|e| {
  1787→            CpError::IoErrContext(
  1788→                e,
  1789→                translate!("cp-error-cannot-create-symlink",
  1790→                           "dest" => get_filename(dest).unwrap_or("?").quote(),
  1791→                           "source" => get_filename(source).unwrap_or("?").quote()),
  1792→            )
  1793→        })?;
  1794→    }
  1795→    #[cfg(windows)]
  1796→    {
  1797→        std::os::windows::fs::symlink_file(source, dest).map_err(|e| {
  1798→            CpError::IoErrContext(
  1799→                e,
  1800→                translate!("cp-error-cannot-create-symlink",
  1801                           "dest" => get_filename(dest).unwrap_or("?").quote(),
  1802→                           "source" => get_filename(source).unwrap_or("?").quote()),
  1803→            )
  1804→        })?;
  1805→    }
  1806→    if let Ok(file_info) = FileInformation::from_path(dest, false) {
  1807→        symlinked_files.insert(file_info);
  1808→    }
  1809→    Ok(())
  1810→}
  1811→
  1812→fn context_for(src: &Path, dest: &Path) -> String {
  1813→    format!("{} -> {}", src.quote(), dest.quote())
  1814→}
