  1816→/// Implements a simple backup copy for the destination file .
  1817→/// if `is_dest_symlink` flag is set to true dest will be renamed to `backup_path`
  1818→/// TODO: for the backup, should this function be replaced by `copy_file(...)`?
  1819→fn backup_dest(dest: &Path, backup_path: &Path, is_dest_symlink: bool) -> CopyResult<PathBuf> {
  1820→    if is_dest_symlink {
  1821→        fs::rename(dest, backup_path)?;
  1822→    } else {
  1823→        fs::copy(dest, backup_path)?;
  1824→    }
  1825→    Ok(backup_path.into())
  1826→}
  1827→
  1828→/// Decide whether source and destination files are the same and
  1829→/// copying is forbidden.
  1830→///
  1831→/// Copying to the same file is only allowed if both `--backup` and
  1832→/// `--force` are specified and the file is a regular file.
  1833→fn is_forbidden_to_copy_to_same_file(
  1834→    source: &Path,
  1835→    dest: &Path,
  1836→    options: &Options,
  1837→    source_in_command_line: bool,
  1838→) -> bool {
  1839→    // TODO To match the behavior of GNU cp, we also need to check
  1840→    // that the file is a regular file.
  1841→    let source_is_symlink = source.is_symlink();
  1842→    let dest_is_symlink = dest.is_symlink();
  1843→    // only disable dereference if both source and dest is symlink and dereference flag is disabled
  1844→    let dereference_to_compare =
  1845→        options.dereference(source_in_command_line) || (!source_is_symlink || !dest_is_symlink);
  1846→    if !paths_refer_to_same_file(source, dest, dereference_to_compare) {
  1847→        return false;
  1848→    }
  1849→    if options.backup != BackupMode::None {
  1850→        if options.force() && !source_is_symlink {
  1851→            return false;
  1852→        }
  1853→        if source_is_symlink && !options.dereference {
  1854→            return false;
  1855→        }
  1856→        if dest_is_symlink {
  1857→            return false;
  1858→        }
  1859→        if !dest_is_symlink && !source_is_symlink && dest != source {
  1860→            return false;
  1861→        }
  1862→    }
  1863→    if options.copy_mode == CopyMode::Link {
  1864→        return false;
  1865→    }
  1866→    if options.copy_mode == CopyMode::SymLink && dest_is_symlink {
  1867→        return false;
  1868→    }
  1869→    // If source and dest are both the same symlink but with different names, then allow the copy.
  1870→    // This can occur, for example, if source and dest are both hardlinks to the same symlink.
  1871→    if dest_is_symlink
  1872→        && source_is_symlink
  1873→        && source.file_name() != dest.file_name()
  1874→        && !options.dereference
  1875→    {
  1876→        return false;
  1877→    }
  1878→    true
  1879→}
  1880→
  1881→/// Back up, remove, or leave intact the destination file, depending on the options.
  1882→fn handle_existing_dest(
  1883→    source: &Path,
  1884→    dest: &Path,
  1885→    options: &Options,
  1886→    source_in_command_line: bool,
  1887→    copied_files: &HashMap<FileInformation, PathBuf>,
  1888→) -> CopyResult<()> {
  1889→    // Disallow copying a file to itself, unless `--force` and
  1890→    // `--backup` are both specified.
  1891→    if is_forbidden_to_copy_to_same_file(source, dest, options, source_in_command_line) {
  1892→        return Err(translate!("cp-error-same-file",
  1893→                       "source" => source.quote(),
  1894→                       "dest" => dest.quote())
  1895→        .into());
  1896→    }
  1897→
  1898→    if options.update == UpdateMode::None {
  1899→        if options.debug {
  1900→            println!("skipped {}", dest.quote());
  1901→        }
  1902→        return Err(CpError::Skipped(false));
  1903→    }
  1904→
  1905→    if options.update != UpdateMode::IfOlder {
  1906→        options.overwrite.verify(dest, options.debug)?;
  1907→    }
  1908→
  1909→    let mut is_dest_removed = false;
  1910→    let backup_path = backup_control::get_backup_path(options.backup, dest, &options.backup_suffix);
  1911→    if let Some(backup_path) = backup_path {
  1912→        if paths_refer_to_same_file(source, &backup_path, true) {
  1913→            return Err(translate!("cp-error-backing-up-destroy-source", "dest" => dest.quote(), "source" => source.quote())
  1914→            .into());
  1915→        }
  1916→        is_dest_removed = dest.is_symlink();
  1917→        backup_dest(dest, &backup_path, is_dest_removed)?;
  1918→    }
  1919→    if !is_dest_removed {
  1920→        delete_dest_if_needed_and_allowed(
  1921→            source,
  1922→            dest,
  1923→            options,
  1924→            source_in_command_line,
  1925→            copied_files,
  1926→        )?;
  1927→    }
  1928→
  1929→    Ok(())
  1930→}
  1931→
  1932→/// Checks if:
  1933→/// * `dest` needs to be deleted before the copy operation can proceed
  1934→/// * the provided options allow this deletion
  1935→///
  1936→/// If so, deletes `dest`.
  1937→fn delete_dest_if_needed_and_allowed(
  1938→    source: &Path,
  1939→    dest: &Path,
  1940→    options: &Options,
  1941→    source_in_command_line: bool,
  1942→    copied_files: &HashMap<FileInformation, PathBuf>,
  1943→) -> CopyResult<()> {
  1944→    let delete_dest = match options.overwrite {
  1945→        OverwriteMode::Clobber(cl) | OverwriteMode::Interactive(cl) => {
  1946→            match cl {
  1947→                ClobberMode::Force => {
  1948→                    // TODO
  1949→                    // Using `readonly` here to check if `dest` needs to be deleted is not correct:
  1950→                    // "On Unix-based platforms this checks if any of the owner, group or others write permission bits are set. It does not check if the current user is in the file's assigned group. It also does not check ACLs. Therefore the return value of this function cannot be relied upon to predict whether attempts to read or write the file will actually succeed."
  1951→                    // This results in some copy operations failing, because this necessary deletion is being skipped.
  1952→                    is_symlink_loop(dest) || fs::metadata(dest)?.permissions().readonly()
  1953→                }
  1954→                ClobberMode::RemoveDestination => true,
  1955→                ClobberMode::Standard => {
  1956→                    // Consider the following files:
  1957→                    //
  1958→                    // * `src/f` - a regular file
  1959→                    // * `src/link` - a hard link to `src/f`
  1960→                    // * `dest/src/f` - a different regular file
  1961→                    //
  1962→                    // In this scenario, if we do `cp -a src/ dest/`, it is
  1963→                    // possible that the order of traversal causes `src/link`
  1964→                    // to get copied first (to `dest/src/link`). In that case,
  1965→                    // in order to make sure `dest/src/link` is a hard link to
  1966→                    // `dest/src/f` and `dest/src/f` has the contents of
  1967→                    // `src/f`, we delete the existing file to allow the hard
  1968→                    // linking.
  1969→                    options.preserve_hard_links() &&
  1970→                            // only try to remove dest file only if the current source
  1971→                            // is hardlink to a file that is already copied
  1972→                            copied_files.contains_key(
  1973→                                &FileInformation::from_path(
  1974→                                    source,
  1975→                                    options.dereference(source_in_command_line)
  1976→                                ).map_err(|e| CpError::IoErrContext(e, format!("cannot stat {}", source.quote())))?
  1977→                            )
  1978→                }
  1979→            }
  1980→        }
  1981→        OverwriteMode::NoClobber => false,
  1982→    };
  1983→
  1984→    if delete_dest {
  1985→        delete_path(dest, options)
  1986→    } else {
  1987→        Ok(())
  1988→    }
  1989→}
  1990→
  1991→fn delete_path(path: &Path, options: &Options) -> CopyResult<()> {
  1992→    // Windows requires clearing readonly attribute before deletion when using --force
  1993→    #[cfg(windows)]
  1994→    if options.force() {
  1995→        if let Ok(mut perms) = fs::metadata(path).map(|m| m.permissions()) {
  1996→            #[allow(clippy::permissions_set_readonly_false)]
  1997→            perms.set_readonly(false);
  1998→            let _ = fs::set_permissions(path, perms);
  1999→        }
  2000→    }
  2001→
  2002→    match fs::remove_file(path) {
  2003→        Ok(()) => {
  2004→            if options.verbose {
  2005→                println!(
  2006→                    "{}",
  2007→                    translate!("cp-verbose-removed", "path" => path.quote())
  2008→                );
  2009→            }
  2010→        }
  2011→        Err(err) if err.kind() == io::ErrorKind::NotFound => {
  2012→            // target could have been deleted earlier (e.g. same-file with --remove-destination)
  2013→        }
  2014→        Err(err) => return Err(err.into()),
  2015→    }
  2016→
  2017→    Ok(())
  2018→}
  2019→
  2020→/// Zip the ancestors of a source path and destination path.
  2021→///
  2022→/// # Examples
  2023→///
  2024→/// ```rust,ignore
  2025→/// let actual = aligned_ancestors(&Path::new("a/b/c"), &Path::new("d/a/b/c"));
  2026→/// let expected = vec![
  2027→///     (Path::new("a"), Path::new("d/a")),
  2028→///     (Path::new("a/b"), Path::new("d/a/b")),
  2029→/// ];
  2030→/// assert_eq!(actual, expected);
  2031→/// ```
  2032→fn aligned_ancestors<'a>(source: &'a Path, dest: &'a Path) -> Vec<(&'a Path, &'a Path)> {
  2033→    // Collect the ancestors of each. For example, if `source` is
  2034→    // "a/b/c", then the ancestors are "a/b/c", "a/b", "a/", and "".
  2035→    let source_ancestors: Vec<&Path> = source.ancestors().collect();
  2036→    let dest_ancestors: Vec<&Path> = dest.ancestors().collect();
  2037→
  2038→    // For this particular application, we don't care about the null
  2039→    // path "" and we don't care about the full path (e.g. "a/b/c"),
  2040→    // so we exclude those.
  2041→    let n = source_ancestors.len();
  2042→    let source_ancestors = &source_ancestors[1..n - 1];
  2043→
  2044→    // Get the matching number of elements from the ancestors of the
  2045→    // destination path (for example, get "d/a" and "d/a/b").
  2046→    let k = source_ancestors.len();
  2047→    let dest_ancestors = &dest_ancestors[1..=k];
  2048→
  2049→    // Now we have two slices of the same length, so we zip them.
  2050→    let mut result = vec![];
  2051→    for (x, y) in source_ancestors
  2052→        .iter()
  2053→        .rev()
  2054→        .zip(dest_ancestors.iter().rev())
  2055→    {
  2056→        result.push((*x, *y));
  2057→    }
  2058→    result
  2059→}
  2060→
  2061→fn print_verbose_output(
  2062→    parents: bool,
  2063→    progress_bar: Option<&ProgressBar>,
  2064→    source: &Path,
  2065→    dest: &Path,
  2066→) {
  2067→    if let Some(pb) = progress_bar {
  2068→        // Suspend (hide) the progress bar so the println won't overlap with the progress bar.
  2069→        pb.suspend(|| {
  2070→            print_paths(parents, source, dest);
  2071→        });
  2072→    } else {
  2073→        print_paths(parents, source, dest);
  2074→    }
  2075→}
  2076→
  2077→fn print_paths(parents: bool, source: &Path, dest: &Path) {
  2078→    if parents {
  2079→        // For example, if copying file `a/b/c` and its parents
  2080→        // to directory `d/`, then print
  2081→        //
  2082→        //     a -> d/a
  2083→        //     a/b -> d/a/b
  2084→        //
  2085→        for (x, y) in aligned_ancestors(source, dest) {
  2086→            println!(
  2087→                "{}",
  2088→                translate!("cp-verbose-created-directory", "source" => x.display(), "dest" => y.display())
  2089→            );
  2090→        }
  2091→    }
  2092→
  2093→    println!("{}", context_for(source, dest));
  2094→}
