  2096→/// Handles the copy mode for a file copy operation.
  2097→///
  2098→/// This function determines how to copy a file based on the provided options.
  2099→/// It supports different copy modes, including hard linking, copying, symbolic linking, updating, and attribute-only copying.
  2100→/// It also handles file backups, overwriting, and dereferencing based on the provided options.
  2101→///
  2102→/// # Returns
  2103→///
  2104→/// * `Ok(())` - The file was copied successfully.
  2105→/// * `Err(CopyError)` - An error occurred while copying the file.
  2106→#[allow(clippy::too_many_arguments)]
  2107→fn handle_copy_mode(
  2108→    source: &Path,
  2109→    dest: &Path,
  2110→    options: &Options,
  2111→    context: &str,
  2112→    source_metadata: &Metadata,
  2113→    symlinked_files: &mut HashSet<FileInformation>,
  2114→    source_in_command_line: bool,
  2115→    source_is_fifo: bool,
  2116→    source_is_socket: bool,
  2117→    created_parent_dirs: &mut HashSet<PathBuf>,
  2118→    #[cfg(unix)] source_is_stream: bool,
  2119→) -> CopyResult<PerformedAction> {
  2120→    let source_is_symlink = source_metadata.is_symlink();
  2121→
  2122→    match options.copy_mode {
  2123→        CopyMode::Link => {
  2124→            if dest.exists() {
  2125→                let backup_path =
  2126→                    backup_control::get_backup_path(options.backup, dest, &options.backup_suffix);
  2127→                if let Some(backup_path) = backup_path {
  2128→                    backup_dest(dest, &backup_path, dest.is_symlink())?;
  2129→                    fs::remove_file(dest)?;
  2130→                }
  2131→                if options.overwrite == OverwriteMode::Clobber(ClobberMode::Force) {
  2132→                    fs::remove_file(dest)?;
  2133→                }
  2134→            }
  2135→            if options.dereference(source_in_command_line) && source.is_symlink() {
  2136→                let resolved =
  2137→                    canonicalize(source, MissingHandling::Missing, ResolveMode::Physical).unwrap();
  2138→                fs::hard_link(resolved, dest)
  2139→            } else {
  2140→                fs::hard_link(source, dest)
  2141→            }
  2142→            .map_err(|e| {
  2143→                CpError::IoErrContext(
  2144→                    e,
  2145→                    translate!("cp-error-cannot-create-hard-link", "dest" => get_filename(dest).unwrap_or("?").quote(), "source" => get_filename(source).unwrap_or("?").quote())
  2146→                )
  2147→            })?;
  2148→        }
  2149→        CopyMode::Copy => {
  2150→            copy_helper(
  2151→                source,
  2152→                dest,
  2153→                options,
  2154→                context,
  2155→                source_is_symlink,
  2156→                source_is_fifo,
  2157→                source_is_socket,
  2158→                symlinked_files,
  2159→                created_parent_dirs,
  2160→                #[cfg(unix)]
  2161→                source_is_stream,
  2162→            )?;
  2163→        }
  2164→        CopyMode::SymLink => {
  2165→            if dest.exists() && options.overwrite == OverwriteMode::Clobber(ClobberMode::Force) {
  2166→                fs::remove_file(dest)?;
  2167→            }
  2168→            symlink_file(source, dest, symlinked_files)?;
  2169→        }
  2170→        CopyMode::Update => {
  2171→            if dest.exists() {
  2172→                match options.update {
  2173→                    UpdateMode::All => {
  2174→                        copy_helper(
  2175→                            source,
  2176→                            dest,
  2177→                            options,
  2178→                            context,
  2179→                            source_is_symlink,
  2180→                            source_is_fifo,
  2181→                            source_is_socket,
  2182→                            symlinked_files,
  2183→                            created_parent_dirs,
  2184→                            #[cfg(unix)]
  2185→                            source_is_stream,
  2186→                        )?;
  2187→                    }
  2188→                    UpdateMode::None => {
  2189→                        if options.debug {
  2190→                            println!("skipped {}", dest.quote());
  2191→                        }
  2192→
  2193→                        return Ok(PerformedAction::Skipped);
  2194→                    }
  2195→                    UpdateMode::NoneFail => {
  2196→                        return Err(CpError::Error(
  2197→                            translate!("cp-error-not-replacing", "file" => dest.quote()),
  2198→                        ));
  2199→                    }
  2200→                    UpdateMode::IfOlder => {
  2201→                        let dest_metadata = fs::symlink_metadata(dest)?;
  2202→
  2203→                        let src_time = source_metadata.modified()?;
  2204→                        let dest_time = dest_metadata.modified()?;
  2205→                        if src_time <= dest_time {
  2206→                            return Ok(PerformedAction::Skipped);
  2207→                        }
  2208→
  2209→                        options.overwrite.verify(dest, options.debug)?;
  2210→
  2211→                        copy_helper(
  2212→                            source,
  2213→                            dest,
  2214→                            options,
  2215→                            context,
  2216→                            source_is_symlink,
  2217→                            source_is_fifo,
  2218→                            source_is_socket,
  2219→                            symlinked_files,
  2220→                            created_parent_dirs,
  2221→                            #[cfg(unix)]
  2222→                            source_is_stream,
  2223→                        )?;
  2224→                    }
  2225→                }
  2226→            } else {
  2227→                copy_helper(
  2228→                    source,
  2229→                    dest,
  2230→                    options,
  2231→                    context,
  2232→                    source_is_symlink,
  2233→                    source_is_fifo,
  2234→                    source_is_socket,
  2235→                    symlinked_files,
  2236→                    created_parent_dirs,
  2237→                    #[cfg(unix)]
  2238→                    source_is_stream,
  2239→                )?;
  2240→            }
  2241→        }
  2242→        CopyMode::AttrOnly => {
  2243→            OpenOptions::new()
  2244→                .write(true)
  2245→                .truncate(false)
  2246→                .create(true)
  2247→                .open(dest)
  2248→                .unwrap();
  2249→        }
  2250→    }
  2251→
  2252→    Ok(PerformedAction::Copied)
  2253→}
  2254→
  2255→/// Calculates the permissions for the destination file in a copy operation.
  2256→///
  2257→/// If the destination file already exists, its current permissions are returned.
  2258→/// If the destination file does not exist, the source file's permissions are used,
  2259→/// with the `no-preserve` option and the umask taken into account on Unix platforms.
  2260→/// # Returns
  2261→///
  2262→/// * `Ok(Permissions)` - The calculated permissions for the destination file.
  2263→/// * `Err(CopyError)` - An error occurred while getting the metadata of the destination file.
  2264→///
  2265→// Allow unused variables for Windows (on options)
  2266→#[allow(unused_variables)]
  2267→fn calculate_dest_permissions(
  2268→    dest_metadata: Option<&Metadata>,
  2269→    dest: &Path,
  2270→    source_metadata: &Metadata,
  2271→    options: &Options,
  2272→    context: &str,
  2273→) -> CopyResult<Permissions> {
  2274→    if let Some(metadata) = dest_metadata {
  2275→        Ok(metadata.permissions())
  2276→    } else {
  2277→        #[cfg(unix)]
  2278→        {
  2279→            let mut permissions = source_metadata.permissions();
  2280→            let mode = handle_no_preserve_mode(options, permissions.mode());
  2281→
  2282→            // Apply umask
  2283→            use uucore::mode::get_umask;
  2284→            let mode = mode & !get_umask();
  2285→            permissions.set_mode(mode);
  2286→            Ok(permissions)
  2287→        }
  2288→        #[cfg(not(unix))]
  2289→        {
  2290→            let permissions = source_metadata.permissions();
  2291→            Ok(permissions)
  2292→        }
  2293→    }
  2294→}
