  2296→/// Copy the a file from `source` to `dest`. `source` will be dereferenced if
  2297→/// `options.dereference` is set to true. `dest` will be dereferenced only if
  2298→/// the source was not a symlink.
  2299→///
  2300→/// Behavior when copying to existing files is contingent on the
  2301→/// `options.overwrite` mode. If a file is skipped, the return type
  2302→/// should be `Error:Skipped`
  2303→///
  2304→/// The original permissions of `source` will be copied to `dest`
  2305→/// after a successful copy.
  2306→#[allow(clippy::cognitive_complexity, clippy::too_many_arguments)]
  2307→fn copy_file(
  2308→    progress_bar: Option<&ProgressBar>,
  2309→    source: &Path,
  2310→    dest: &Path,
  2311→    options: &Options,
  2312→    symlinked_files: &mut HashSet<FileInformation>,
  2313→    copied_destinations: &HashSet<PathBuf>,
  2314→    copied_files: &mut HashMap<FileInformation, PathBuf>,
  2315→    created_parent_dirs: &mut HashSet<PathBuf>,
  2316→    source_in_command_line: bool,
  2317→) -> CopyResult<()> {
  2318→    let source_is_symlink = source.is_symlink();
  2319→    let initial_dest_metadata = dest.symlink_metadata().ok();
  2320→    let dest_is_symlink = initial_dest_metadata
  2321→        .as_ref()
  2322→        .map(|md| md.file_type().is_symlink())
  2323→        .unwrap_or(false);
  2324→    let dest_target_exists = dest.try_exists().unwrap_or(false);
  2325→    // Fail if dest is a dangling symlink or a symlink this program created previously
  2326→    if dest_is_symlink {
  2327→        if FileInformation::from_path(dest, false)
  2328→            .map(|info| symlinked_files.contains(&info))
  2329→            .unwrap_or(false)
  2330→        {
  2331→            return Err(CpError::Error(
  2332→                translate!("cp-error-will-not-copy-through-symlink", "source" => source.quote(), "dest" => dest.quote()),
  2333→            ));
  2334→        }
  2335→        // Fail if cp tries to copy two sources of the same name into a single symlink
  2336→        // Example: "cp file1 dir1/file1 tmp" where "tmp" is a directory containing a symlink "file1" pointing to a file named "foo".
  2337→        // foo will contain the contents of "file1" and "dir1/file1" will not be copied over to "tmp/file1"
  2338→        if copied_destinations.contains(dest) {
  2339→            return Err(CpError::Error(
  2340→                translate!("cp-error-will-not-copy-through-symlink", "source" => source.quote(), "dest" => dest.quote()),
  2341→            ));
  2342→        }
  2343→
  2344→        let copy_contents = options.dereference(source_in_command_line) || !source_is_symlink;
  2345→        if copy_contents
  2346→            && !dest_target_exists
  2347→            && !matches!(
  2348→                options.overwrite,
  2349→                OverwriteMode::Clobber(ClobberMode::RemoveDestination)
  2350→            )
  2351→            && !is_symlink_loop(dest)
  2352→            && std::env::var_os("POSIXLY_CORRECT").is_none()
  2353→        {
  2354→            return Err(CpError::Error(
  2355→                translate!("cp-error-not-writing-dangling-symlink", "dest" => dest.quote()),
  2356→            ));
  2357→        }
  2358→        if paths_refer_to_same_file(source, dest, true)
  2359→            && matches!(
  2360→                options.overwrite,
  2361→                OverwriteMode::Clobber(ClobberMode::RemoveDestination)
  2362→            )
  2363→            && options.backup == BackupMode::None
  2364→        {
  2365→            fs::remove_file(dest)?;
  2366→        }
  2367→    }
  2368→
  2369→    if are_hardlinks_to_same_file(source, dest)
  2370→        && source != dest
  2371→        && matches!(
  2372→            options.overwrite,
  2373→            OverwriteMode::Clobber(ClobberMode::RemoveDestination)
  2374→        )
  2375→    {
  2376→        fs::remove_file(dest)?;
  2377→    }
  2378→
  2379→    if initial_dest_metadata.is_some()
  2380→        && (!options.attributes_only
  2381→            || matches!(
  2382→                options.overwrite,
  2383→                OverwriteMode::Clobber(ClobberMode::RemoveDestination)
  2384→            ))
  2385→    {
  2386→        if paths_refer_to_same_file(source, dest, true) && options.copy_mode == CopyMode::Link {
  2387→            if source_is_symlink {
  2388→                if !dest_is_symlink {
  2389→                    return Ok(());
  2390→                }
  2391→                if !options.dereference {
  2392→                    return Ok(());
  2393→                }
  2394→            } else if options.backup != BackupMode::None && !dest_is_symlink {
  2395→                if source == dest {
  2396→                    if !options.force() {
  2397→                        return Ok(());
  2398→                    }
  2399→                } else {
  2400→                    return Ok(());
  2401→                }
  2402→            }
  2403→        }
  2404→        handle_existing_dest(source, dest, options, source_in_command_line, copied_files)?;
  2405→        if are_hardlinks_to_same_file(source, dest) {
  2406→            if options.copy_mode == CopyMode::Copy {
  2407→                return Ok(());
  2408→            }
  2409→            if options.copy_mode == CopyMode::Link && (!source_is_symlink || !dest_is_symlink) {
  2410→                return Ok(());
  2411→            }
  2412→        }
  2413→    }
  2414→
  2415→    if options.attributes_only
  2416→        && source_is_symlink
  2417→        && !matches!(
  2418→            options.overwrite,
  2419→            OverwriteMode::Clobber(ClobberMode::RemoveDestination)
  2420→        )
  2421→    {
  2422→        return Err(translate!("cp-error-cannot-change-attribute", "dest" => dest.quote()).into());
  2423→    }
  2424→
  2425→    if options.preserve_hard_links() {
  2426→        // if we encounter a matching device/inode pair in the source tree
  2427→        // we can arrange to create a hard link between the corresponding names
  2428→        // in the destination tree.
  2429→        if let Some(new_source) = copied_files.get(
  2430→            &FileInformation::from_path(source, options.dereference(source_in_command_line))
  2431→                .map_err(|e| CpError::IoErrContext(e, format!("cannot stat {}", source.quote())))?,
  2432→        ) {
  2433→            fs::hard_link(new_source, dest)?;
  2434→
  2435→            if options.verbose {
  2436→                print_verbose_output(options.parents, progress_bar, source, dest);
  2437→            }
  2438→
  2439→            return Ok(());
  2440→        }
  2441→    }
  2442→
  2443→    // Calculate the context upfront before canonicalizing the path
  2444→    let context = context_for(source, dest);
  2445→    let context = context.as_str();
  2446→
  2447→    let source_metadata = {
  2448→        let result = if options.dereference(source_in_command_line) {
  2449→            fs::metadata(source)
  2450→        } else {
  2451→            fs::symlink_metadata(source)
  2452→        };
  2453→        // this is just for gnu tests compatibility
  2454→        result.map_err(|err| {
  2455→            if err.to_string().contains("No such file or directory") {
  2456→                return translate!("cp-error-cannot-stat", "source" => source.quote());
  2457→            }
  2458→            err.to_string()
  2459→        })?
  2460→    };
  2461→
  2462→    let dest_metadata = dest.symlink_metadata().ok();
  2463→
  2464→    let dest_permissions = calculate_dest_permissions(
  2465→        dest_metadata.as_ref(),
  2466→        dest,
  2467→        &source_metadata,
  2468→        options,
  2469→        context,
  2470→    )?;
  2471→
  2472→    #[cfg(unix)]
  2473→    let source_is_fifo = source_metadata.file_type().is_fifo();
  2474→    #[cfg(unix)]
  2475→    let source_is_socket = source_metadata.file_type().is_socket();
  2476→    #[cfg(not(unix))]
  2477→    let source_is_fifo = false;
  2478→    #[cfg(not(unix))]
  2479→    let source_is_socket = false;
  2480→
  2481→    let source_is_stream = is_stream(&source_metadata);
  2482→
  2483→    let performed_action = handle_copy_mode(
  2484→        source,
  2485→        dest,
  2486→        options,
  2487→        context,
  2488→        &source_metadata,
  2489→        symlinked_files,
  2490→        source_in_command_line,
  2491→        source_is_fifo,
  2492→        source_is_socket,
  2493→        created_parent_dirs,
  2494→        #[cfg(unix)]
  2495→        source_is_stream,
  2496→    )?;
  2497→
  2498→    if options.verbose && performed_action != PerformedAction::Skipped {
  2499→        print_verbose_output(options.parents, progress_bar, source, dest);
  2500→    }
  2501→
  2502→    // TODO: implement something similar to gnu's lchown
  2503→    if !dest_is_symlink {
  2504→        // Here, to match GNU semantics, we quietly ignore an error
  2505→        // if a user does not have the correct ownership to modify
  2506→        // the permissions of a file.
  2507→        //
  2508→        // FWIW, the OS will throw an error later, on the write op, if
  2509→        // the user does not have permission to write to the file.
  2510→        fs::set_permissions(dest, dest_permissions).ok();
  2511→    }
  2512→
  2513→    if options.dereference(source_in_command_line) {
  2514→        if let Ok(src) = canonicalize(source, MissingHandling::Normal, ResolveMode::Physical) {
  2515→            if src.exists() {
  2516→                copy_attributes(&src, dest, &options.attributes)?;
  2517→            }
  2518→        }
  2519→    } else if source_is_stream && !source.exists() {
  2520→        // Some stream files may not exist after we have copied it,
  2521→        // like anonymous pipes. Thus, we can't really copy its
  2522→        // attributes. However, this is already handled in the stream
  2523→        // copy function (see `copy_stream` under platform/linux.rs).
  2524→    } else {
  2525→        copy_attributes(source, dest, &options.attributes)?;
  2526→    }
  2527→
  2528→    #[cfg(feature = "selinux")]
  2529→    if options.set_selinux_context && uucore::selinux::is_selinux_enabled() {
  2530→        // Set the given selinux permissions on the copied file.
  2531→        if let Err(e) =
  2532→            uucore::selinux::set_selinux_security_context(dest, options.context.as_ref())
  2533→        {
  2534→            return Err(CpError::Error(
  2535→                translate!("cp-error-selinux-error", "error" => e),
  2536→            ));
  2537→        }
  2538→    }
  2539→
  2540→    copied_files.insert(
  2541→        FileInformation::from_path(source, options.dereference(source_in_command_line))?,
  2542→        dest.to_path_buf(),
  2543→    );
  2544→
  2545→    if let Some(progress_bar) = progress_bar {
  2546→        progress_bar.inc(source_metadata.len());
  2547→    }
  2548→
  2549→    Ok(())
  2550→}
  2551→
  2552→fn is_stream(metadata: &Metadata) -> bool {
  2553→    #[cfg(unix)]
  2554→    {
  2555→        let file_type = metadata.file_type();
  2556→        file_type.is_fifo() || file_type.is_char_device() || file_type.is_block_device()
  2557→    }
  2558→    #[cfg(not(unix))]
  2559→    {
  2560→        let _ = metadata;
  2561→        false
  2562→    }
  2563→}
  2564→
  2565→#[cfg(unix)]
  2566→fn handle_no_preserve_mode(options: &Options, org_mode: u32) -> u32 {
  2567→    let (is_preserve_mode, is_explicit_no_preserve_mode) = options.preserve_mode();
  2568→    if !is_preserve_mode {
  2569→        use libc::{
  2570→            S_IRGRP, S_IROTH, S_IRUSR, S_IRWXG, S_IRWXO, S_IRWXU, S_IWGRP, S_IWOTH, S_IWUSR,
  2571→        };
  2572→
  2573→        #[cfg(not(any(
  2574→            target_os = "android",
  2575→            target_os = "macos",
  2576→            target_os = "freebsd",
  2577→            target_os = "redox",
  2578→        )))]
  2579→        {
  2580→            const MODE_RW_UGO: u32 = S_IRUSR | S_IWUSR | S_IRGRP | S_IWGRP | S_IROTH | S_IWOTH;
  2581→            const S_IRWXUGO: u32 = S_IRWXU | S_IRWXG | S_IRWXO;
  2582→            return if is_explicit_no_preserve_mode {
  2583→                MODE_RW_UGO
  2584→            } else {
  2585→                org_mode & S_IRWXUGO
  2586→            };
  2587→        }
  2588→
  2589→        #[cfg(any(
  2590→            target_os = "android",
  2591→            target_os = "macos",
  2592→            target_os = "freebsd",
  2593→            target_os = "redox",
  2594→        ))]
  2595→        {
  2596→            const MODE_RW_UGO: u32 =
  2597→                (S_IRUSR | S_IWUSR | S_IRGRP | S_IWGRP | S_IROTH | S_IWOTH) as u32;
  2598→            const S_IRWXUGO: u32 = (S_IRWXU | S_IRWXG | S_IRWXO) as u32;
  2599→            return if is_explicit_no_preserve_mode {
  2600→                MODE_RW_UGO
  2601→            } else {
  2602→                org_mode & S_IRWXUGO
  2603→            };
  2604→        }
  2605→    }
  2606→
  2607→    org_mode
  2608→}
