  2610→/// Copy the file from `source` to `dest` either using the normal `fs::copy` or a
  2611→/// copy-on-write scheme if --reflink is specified and the filesystem supports it.
  2612→#[allow(clippy::too_many_arguments)]
  2613→fn copy_helper(
  2614→    source: &Path,
  2615→    dest: &Path,
  2616→    options: &Options,
  2617→    context: &str,
  2618→    source_is_symlink: bool,
  2619→    source_is_fifo: bool,
  2620→    source_is_socket: bool,
  2621→    symlinked_files: &mut HashSet<FileInformation>,
  2622→    created_parent_dirs: &mut HashSet<PathBuf>,
  2623→    #[cfg(unix)] source_is_stream: bool,
  2624→) -> CopyResult<()> {
  2625→    if options.parents {
  2626→        let parent = dest.parent().unwrap_or(dest);
  2627→        if created_parent_dirs.insert(parent.to_path_buf()) {
  2628→            fs::create_dir_all(parent)?;
  2629→        }
  2630→    }
  2631→
  2632→    if path_ends_with_terminator(dest) && !dest.is_dir() {
  2633→        return Err(CpError::NotADirectory(dest.to_path_buf()));
  2634→    }
  2635→
  2636→    if source_is_socket && options.recursive && !options.copy_contents {
  2637→        #[cfg(unix)]
  2638→        copy_socket(dest, options.overwrite, options.debug)?;
  2639→    } else if source_is_fifo && options.recursive && !options.copy_contents {
  2640→        #[cfg(unix)]
  2641→        copy_fifo(dest, options.overwrite, options.debug)?;
  2642→    } else if source_is_symlink {
  2643→        copy_link(source, dest, symlinked_files, options)?;
  2644→    } else {
  2645→        let copy_debug = copy_on_write(
  2646→            source,
  2647→            dest,
  2648→            options.reflink_mode,
  2649→            options.sparse_mode,
  2650→            context,
  2651→            #[cfg(unix)]
  2652→            source_is_stream,
  2653→        )?;
  2654→
  2655→        if !options.attributes_only && options.debug {
  2656→            show_debug(&copy_debug);
  2657→        }
  2658→    }
  2659→
  2660→    Ok(())
  2661→}
  2662→
  2663→// "Copies" a FIFO by creating a new one. This workaround is because Rust's
  2664→// built-in fs::copy does not handle FIFOs (see rust-lang/rust/issues/79390).
  2665→#[cfg(unix)]
  2666→fn copy_fifo(dest: &Path, overwrite: OverwriteMode, debug: bool) -> CopyResult<()> {
  2667→    if dest.exists() {
  2668→        overwrite.verify(dest, debug)?;
  2669→        fs::remove_file(dest)?;
  2670→    }
  2671→
  2672→    make_fifo(dest)
  2673→        .map_err(|_| translate!("cp-error-cannot-create-fifo", "path" => dest.quote()).into())
  2674→}
  2675→
  2676→#[cfg(unix)]
  2677→fn copy_socket(dest: &Path, overwrite: OverwriteMode, debug: bool) -> CopyResult<()> {
  2678→    if dest.exists() {
  2679→        overwrite.verify(dest, debug)?;
  2680→        fs::remove_file(dest)?;
  2681→    }
  2682→
  2683→    UnixListener::bind(dest)?;
  2684→    Ok(())
  2685→}
  2686→
  2687→fn copy_link(
  2688→    source: &Path,
  2689→    dest: &Path,
  2690→    symlinked_files: &mut HashSet<FileInformation>,
  2691→    options: &Options,
  2692→) -> CopyResult<()> {
  2693→    // Here, we will copy the symlink itself (actually, just recreate it)
  2694→    let link = fs::read_link(source)?;
  2695→    // we always need to remove the file to be able to create a symlink,
  2696→    // even if it is writeable.
  2697→    if dest.is_symlink() || dest.is_file() {
  2698→        delete_path(dest, options)?;
  2699→    }
  2700→    symlink_file(&link, dest, symlinked_files)?;
  2701→    copy_attributes(source, dest, &options.attributes)
  2702→}
