  2704→/// Generate an error message if `target` is not the correct `target_type`
  2705→pub fn verify_target_type(target: &Path, target_type: &TargetType) -> CopyResult<()> {
  2706→    match (target_type, target.is_dir()) {
  2707→        (&TargetType::Directory, false) => Err(translate!("cp-error-target-not-directory", "target" => target.quote())
  2708→        .into()),
  2709→        (&TargetType::File, true) => Err(translate!("cp-error-cannot-overwrite-directory-with-non-directory", "dir" => target.quote())
  2710→        .into()),
  2711→        _ => Ok(()),
  2712→    }
  2713→}
  2714→
  2715→/// Remove the `root` prefix from `source` and prefix it with `target`
  2716→/// to create a file that is local to `target`
  2717→/// # Examples
  2718→///
  2719→/// ```ignore
  2720→/// assert!(uu_cp::localize_to_target(
  2721→///     &Path::new("a/source/"),
  2722→///     &Path::new("a/source/c.txt"),
  2723→///     &Path::new("target/"),
  2724→/// ).unwrap() == Path::new("target/c.txt"))
  2725→/// ```
  2726→pub fn localize_to_target(root: &Path, source: &Path, target: &Path) -> CopyResult<PathBuf> {
  2727→    let local_to_root = source.strip_prefix(root)?;
  2728→    Ok(target.join(local_to_root))
  2729→}
  2730→
  2731→/// Get the total size of a slice of files and directories.
  2732→///
  2733→/// This function is much like the `du` utility, by recursively getting the sizes of files in directories.
  2734→/// Files are not deduplicated when appearing in multiple sources. If `recursive` is set to `false`, the
  2735→/// directories in `paths` will be ignored.
  2736→fn disk_usage(paths: &[PathBuf], recursive: bool) -> io::Result<u64> {
  2737→    let mut total = 0;
  2738→    for p in paths {
  2739→        let md = fs::metadata(p)?;
  2740→        if md.file_type().is_dir() {
  2741→            if recursive {
  2742→                total += disk_usage_directory(p)?;
  2743→            }
  2744→        } else {
  2745→            total += md.len();
