    24→/// The fallback behavior for [`clone`] on failed system call.
    25→#[derive(Clone, Copy)]
    26→enum CloneFallback {
    27→    /// Raise an error.
    28→    Error,
    29→
    30→    /// Use [`std::fs::copy`].
    31→    FSCopy,
    32→
    33→    /// Use [`sparse_copy`]
    34→    SparseCopy,
    35→
    36→    /// Use [`sparse_copy_without_hole`]
    37→    SparseCopyWithoutHole,
    38→}
    39→
    40→/// Type of method used for copying files
    41→#[derive(Clone, Copy)]
    42→enum CopyMethod {
    43→    /// Do a sparse copy
    44→    SparseCopy,
    45→    /// Use [`std::fs::copy`].
    46→    FSCopy,
    47→    /// Default (can either be [`CopyMethod::SparseCopy`] or [`CopyMethod::FSCopy`])
    48→    Default,
    49→    /// Use [`sparse_copy_without_hole`]
    50→    SparseCopyWithoutHole,
    51→}
    52→
    53→/// Use the Linux `ioctl_ficlone` API to do a copy-on-write clone.
    54→///
    55→/// `fallback` controls what to do if the system call fails.
    56→#[cfg(any(target_os = "linux", target_os = "android"))]
    57→fn clone<P>(source: P, dest: P, fallback: CloneFallback) -> std::io::Result<()>
    58→where
    59→    P: AsRef<Path>,
    60→{
    61→    let src_file = File::open(&source)?;
    62→    let dst_file = File::create(&dest)?;
    63→    let src_fd = src_file.as_raw_fd();
    64→    let dst_fd = dst_file.as_raw_fd();
    65→    let result = unsafe { libc::ioctl(dst_fd, libc::FICLONE, src_fd) };
    66→    if result == 0 {
    67→        return Ok(());
    68→    }
    69→    match fallback {
    70→        CloneFallback::Error => Err(std::io::Error::last_os_error()),
    71→        CloneFallback::FSCopy => std::fs::copy(source, dest).map(|_| ()),
    72→        CloneFallback::SparseCopy => sparse_copy(source, dest),
    73→        CloneFallback::SparseCopyWithoutHole => sparse_copy_without_hole(source, dest),
    74→    }
    75→}
    76→
    77→/// Checks whether a file contains any non null bytes i.e. any byte != 0x0
    78→/// This function returns a tuple of (bool, u64, u64) signifying a tuple of (whether a file has
    79→/// data, its size, no of blocks it has allocated in disk)
    80→#[cfg(any(target_os = "linux", target_os = "android"))]
    81→fn check_for_data(source: &Path) -> Result<(bool, u64, u64), std::io::Error> {
    82→    let mut src_file = File::open(source)?;
    83→    let metadata = src_file.metadata()?;
    84→
    85→    let size = metadata.size();
    86→    let blocks = metadata.blocks();
    87→    // checks edge case of virtual files in /proc which have a size of zero but contains data
    88→    if size == 0 {
    89→        let mut buf: Vec<u8> = vec![0; metadata.blksize() as usize]; // Directly use metadata.blksize()
    90→        let _ = src_file.read(&mut buf)?;
    91→        return Ok((buf.iter().any(|&x| x != 0x0), size, 0));
    92→    }
    93→
    94→    let src_fd = src_file.as_raw_fd();
    95→
    96→    let result = unsafe { libc::lseek(src_fd, 0, SEEK_DATA) };
    97→
    98→    match result {
    99→        -1 => Ok((false, size, blocks)), // No data found or end of file
   100→        _ if result >= 0 => Ok((true, size, blocks)), // Data found
   101→        _ => Err(std::io::Error::last_os_error()),
   102→    }
   103→}
   104→
   105→#[cfg(any(target_os = "linux", target_os = "android"))]
   106→/// Checks whether a file is sparse i.e. it contains holes, uses the crude heuristic blocks < size / 512
   107→/// Reference:`<https://doc.rust-lang.org/std/os/unix/fs/trait.MetadataExt.html#tymethod.blocks>`
   108→fn check_sparse_detection(source: &Path) -> Result<bool, std::io::Error> {
   109→    let src_file = File::open(source)?;
   110→    let metadata = src_file.metadata()?;
   111→    let size = metadata.size();
   112→    let blocks = metadata.blocks();
   113→
   114→    if blocks < size / 512 {
   115→        return Ok(true);
   116→    }
   117→    Ok(false)
   118→}
   119→
   120→/// Optimized [`sparse_copy`] doesn't create holes for large sequences of zeros in non `sparse_files`
   121→/// Used when `--sparse=auto`
   122→#[cfg(any(target_os = "linux", target_os = "android"))]
   123→fn sparse_copy_without_hole<P>(source: P, dest: P) -> std::io::Result<()>
   124→where
   125→    P: AsRef<Path>,
   126→{
   127→    let src_file = File::open(source)?;
   128→    let dst_file = File::create(dest)?;
   129→    let dst_fd = dst_file.as_raw_fd();
   130→
   131→    let size = src_file.metadata()?.size();
   132→    if unsafe { libc::ftruncate(dst_fd, size.try_into().unwrap()) } < 0 {
   133→        return Err(std::io::Error::last_os_error());
   134→    }
   135→    let src_fd = src_file.as_raw_fd();
   136→    let mut current_offset: isize = 0;
   137→    // Maximize the data read at once to 16 MiB to avoid memory hogging with large files
   138→    // 16 MiB chunks should saturate an SSD
   139→    let step = std::cmp::min(size, 16 * 1024 * 1024) as usize;
   140→    let mut buf: Vec<u8> = vec![0x0; step];
   141→    loop {
   142→        let result = unsafe { libc::lseek(src_fd, current_offset.try_into().unwrap(), SEEK_DATA) }
   143→            .try_into()
   144→            .unwrap();
   145→
   146→        current_offset = result;
   147→        let hole: isize =
   148→            unsafe { libc::lseek(src_fd, current_offset.try_into().unwrap(), SEEK_HOLE) }
   149→                .try_into()
   150→                .unwrap();
   151→        if result == -1 || hole == -1 {
   152→            break;
   153→        }
   154→        if result <= -2 || hole <= -2 {
   155→            return Err(std::io::Error::last_os_error());
   156→        }
   157→        let len: isize = hole - current_offset;
   158→        // Read and write data in chunks of `step` while reusing the same buffer
   159→        for i in (0..len).step_by(step) {
   160→            // Ensure we don't read past the end of the file or the start of the next hole
   161→            let read_len = std::cmp::min((len - i) as usize, step);
   162→            let buf = &mut buf[..read_len];
   163→            src_file.read_exact_at(buf, (current_offset + i) as u64)?;
   164→            dst_file.write_all_at(buf, (current_offset + i) as u64)?;
   165→        }
   166→        current_offset = hole;
   167→    }
   168→    Ok(())
   169→}
   170→/// Perform a sparse copy from one file to another.
   171→/// Creates a holes for large sequences of zeros in `non_sparse_files`, used for `--sparse=always`
   172→#[cfg(any(target_os = "linux", target_os = "android"))]
   173→fn sparse_copy<P>(source: P, dest: P) -> std::io::Result<()>
   174→where
   175→    P: AsRef<Path>,
   176→{
   177→    let mut src_file = File::open(source)?;
   178→    let dst_file = File::create(dest)?;
   179→    let dst_fd = dst_file.as_raw_fd();
   180→
   181→    let size: usize = src_file.metadata()?.size().try_into().unwrap();
   182→    if unsafe { libc::ftruncate(dst_fd, size.try_into().unwrap()) } < 0 {
   183→        return Err(std::io::Error::last_os_error());
   184→    }
   185→
   186→    let blksize = dst_file.metadata()?.blksize();
   187→    let mut buf: Vec<u8> = vec![0; blksize.try_into().unwrap()];
   188→    let mut current_offset: usize = 0;
   189→
   190→    // TODO Perhaps we can employ the "fiemap ioctl" API to get the
   191→    // file extent mappings:
   192→    // https://www.kernel.org/doc/html/latest/filesystems/fiemap.html
   193→    while current_offset < size {
   194→        let this_read = src_file.read(&mut buf)?;
   195→        let buf = &buf[..this_read];
   196→        if buf.iter().any(|&x| x != 0) {
   197→            dst_file.write_all_at(buf, current_offset.try_into().unwrap())?;
   198→        }
   199→        current_offset += this_read;
   200→    }
   201→    Ok(())
   202→}
