   204→#[cfg(any(target_os = "linux", target_os = "android"))]
   205→/// Checks whether an existing destination is a fifo
   206→fn check_dest_is_fifo(dest: &Path) -> bool {
   207→    // If our destination file exists and its a fifo , we do a standard copy .
   208→    let file_type = std::fs::metadata(dest);
   209→    match file_type {
   210→        Ok(f) => f.file_type().is_fifo(),
   211→
   212→        _ => false,
   213→    }
   214→}
