   216→/// Copy the contents of a stream from `source` to `dest`.
   217→fn copy_stream<P>(source: P, dest: P) -> std::io::Result<u64>
   218→where
   219→    P: AsRef<Path>,
   220→{
   221→    // For some reason,
   222→    //
   223→    //     cp --preserve=ownership --copy-contents fifo fifo2
   224→    //
   225→    // causes `fifo2` to be created with limited permissions (mode 622
   226→    // or maybe 600 it seems), and then after `fifo` is closed, the
   227→    // permissions get updated to match those of `fifo`. This doesn't
   228→    // make much sense to me but the behavior appears in
   229→    // `tests/cp/file-perm-race.sh`.
   230→    //
   231→    // So it seems that if `--preserve=ownership` is true then what we
   232→    // need to do is create the destination file with limited
   233→    // permissions, copy the contents, then update the permissions. If
   234→    // `--preserve=ownership` is not true, however, then we can just
   235→    // match the mode of the source file.
   236→    //
   237→    // TODO Update the code below to respect the case where
   238→    // `--preserve=ownership` is not true.
   239→    let mut src_file = File::open(&source)?;
   240→    let mode = 0o622 & !get_umask();
   241→    let mut dst_file = OpenOptions::new()
   242→        .create(true)
   243→        .write(true)
   244→        .mode(mode)
   245→        .open(&dest)?;
   246→
   247→    let dest_is_stream = is_stream(&dst_file.metadata()?);
   248→    if !dest_is_stream {
   249→        // `copy_stream` doesn't clear the dest file, if dest is not a stream, we should clear it manually.
   250→        dst_file.set_len(0)?;
   251→    }
   252→
   253→    let num_bytes_copied = buf_copy::copy_stream(&mut src_file, &mut dst_file)
   254→        .map_err(|_| std::io::Error::from(std::io::ErrorKind::Other))?;
   255→
   256→    Ok(num_bytes_copied)
   257→}
   258→
   259→/// Copies `source` to `dest` using copy-on-write if possible.
   260→pub(crate) fn copy_on_write(
   261→    source: &Path,
   262→    dest: &Path,
   263→    reflink_mode: ReflinkMode,
   264→    sparse_mode: SparseMode,
   265→    context: &str,
   266→    source_is_stream: bool,
   267→) -> CopyResult<CopyDebug> {
   268→    let mut copy_debug = CopyDebug {
   269→        offload: OffloadReflinkDebug::Unknown,
   270→        reflink: OffloadReflinkDebug::Unsupported,
   271→        sparse_detection: SparseDebug::No,
   272→    };
   273→    let result = match (reflink_mode, sparse_mode) {
   274→        (ReflinkMode::Never, SparseMode::Always) => {
   275→            copy_debug.sparse_detection = SparseDebug::Zeros;
   276→            // Default SparseDebug val for SparseMode::Always
   277→            copy_debug.reflink = OffloadReflinkDebug::No;
   278→            if source_is_stream {
   279→                copy_debug.offload = OffloadReflinkDebug::Avoided;
   280→                copy_stream(source, dest).map(|_| ())
   281→            } else {
   282→                let mut copy_method = CopyMethod::Default;
   283→                let result = handle_reflink_never_sparse_always(source, dest);
   284→                if let Ok((debug, method)) = result {
   285→                    copy_debug = debug;
   286→                    copy_method = method;
   287→                }
   288→
   289→                match copy_method {
   290→                    CopyMethod::FSCopy => std::fs::copy(source, dest).map(|_| ()),
   291→                    _ => sparse_copy(source, dest),
   292→                }
   293→            }
   294→        }
   295→        (ReflinkMode::Never, SparseMode::Never) => {
   296→            copy_debug.reflink = OffloadReflinkDebug::No;
   297→
   298→            if source_is_stream {
   299→                copy_debug.offload = OffloadReflinkDebug::Avoided;
   300→                copy_stream(source, dest).map(|_| ())
   301→            } else {
   302→                let result = handle_reflink_never_sparse_never(source);
   303→                if let Ok(debug) = result {
   304→                    copy_debug = debug;
   305→                }
   306→                std::fs::copy(source, dest).map(|_| ())
   307→            }
   308→        }
   309→        (ReflinkMode::Never, SparseMode::Auto) => {
   310→            copy_debug.reflink = OffloadReflinkDebug::No;
   311→
   312→            if source_is_stream {
   313→                copy_debug.offload = OffloadReflinkDebug::Avoided;
   314→                copy_stream(source, dest).map(|_| ())
   315→            } else {
   316→                let mut copy_method = CopyMethod::Default;
   317→                let result = handle_reflink_never_sparse_auto(source, dest);
   318→                if let Ok((debug, method)) = result {
   319→                    copy_debug = debug;
   320→                    copy_method = method;
   321→                }
   322→
   323→                match copy_method {
   324→                    CopyMethod::SparseCopyWithoutHole => sparse_copy_without_hole(source, dest),
   325→                    _ => std::fs::copy(source, dest).map(|_| ()),
   326→                }
   327→            }
   328→        }
   329→        (ReflinkMode::Auto, SparseMode::Always) => {
   330→            copy_debug.sparse_detection = SparseDebug::Zeros; // Default SparseDebug val for
   331→            // SparseMode::Always
   332→            if source_is_stream {
   333→                copy_debug.offload = OffloadReflinkDebug::Avoided;
   334→                copy_stream(source, dest).map(|_| ())
   335→            } else {
   336→                let mut copy_method = CopyMethod::Default;
   337→                let result = handle_reflink_auto_sparse_always(source, dest);
   338→                if let Ok((debug, method)) = result {
   339→                    copy_debug = debug;
   340→                    copy_method = method;
   341→                }
   342→
   343→                match copy_method {
   344→                    CopyMethod::FSCopy => clone(source, dest, CloneFallback::FSCopy),
   345→                    _ => clone(source, dest, CloneFallback::SparseCopy),
   346→                }
   347→            }
   348→        }
   349→
   350→        (ReflinkMode::Auto, SparseMode::Never) => {
   351→            copy_debug.reflink = OffloadReflinkDebug::No;
   352→            if source_is_stream {
   353→                copy_debug.offload = OffloadReflinkDebug::Avoided;
   354→                copy_stream(source, dest).map(|_| ())
   355→            } else {
   356→                let result = handle_reflink_auto_sparse_never(source);
   357→                if let Ok(debug) = result {
   358→                    copy_debug = debug;
   359→                }
   360→
   361→                clone(source, dest, CloneFallback::FSCopy)
   362→            }
   363→        }
   364→        (ReflinkMode::Auto, SparseMode::Auto) => {
   365→            if source_is_stream {
   366→                copy_debug.offload = OffloadReflinkDebug::Unsupported;
   367→                copy_stream(source, dest).map(|_| ())
   368→            } else {
   369→                let mut copy_method = CopyMethod::Default;
   370→                let result = handle_reflink_auto_sparse_auto(source, dest);
   371→                if let Ok((debug, method)) = result {
   372→                    copy_debug = debug;
   373→                    copy_method = method;
   374→                }
   375→
   376→                match copy_method {
   377→                    CopyMethod::SparseCopyWithoutHole => {
   378→                        clone(source, dest, CloneFallback::SparseCopyWithoutHole)
   379→                    }
   380→                    _ => clone(source, dest, CloneFallback::FSCopy),
   381→                }
   382→            }
   383→        }
   384→
   385→        (ReflinkMode::Always, SparseMode::Auto) => {
   386→            copy_debug.sparse_detection = SparseDebug::No;
   387→            copy_debug.reflink = OffloadReflinkDebug::Yes;
   388→
   389→            clone(source, dest, CloneFallback::Error)
   390→        }
   391→        (ReflinkMode::Always, _) => {
   392→            return Err(translate!("cp-error-reflink-always-sparse-auto").into());
   393→        }
   394→    };
   395→    result.map_err(|e| CpError::IoErrContext(e, context.to_owned()))?;
   396→    Ok(copy_debug)
   397→}
   398→
   399→/// Handles debug results when flags are "--reflink=auto" and "--sparse=always" and specifies what
   400→/// type of copy should be used
   401→fn handle_reflink_auto_sparse_always(
   402→    source: &Path,
   403→    dest: &Path,
   404→) -> Result<(CopyDebug, CopyMethod), std::io::Error> {
   405→    let mut copy_debug = CopyDebug {
   406→        offload: OffloadReflinkDebug::Unknown,
   407→        reflink: OffloadReflinkDebug::Unsupported,
   408→        sparse_detection: SparseDebug::Zeros,
   409→    };
   410→    let mut copy_method = CopyMethod::Default;
   411→    let (data_flag, size, blocks) = check_for_data(source)?;
   412→    let sparse_flag = check_sparse_detection(source)?;
   413→
   414→    if data_flag || size < 512 {
   415→        copy_debug.offload = OffloadReflinkDebug::Avoided;
   416→    }
   417→    match (sparse_flag, data_flag, blocks) {
   418→        (true, true, 0) => {
   419→            // Handling funny files with 0 block allocation but has data
   420→            // in it
   421→            copy_method = CopyMethod::FSCopy;
   422→            copy_debug.sparse_detection = SparseDebug::SeekHoleZeros;
   423→        }
   424→        (false, true, 0) => copy_method = CopyMethod::FSCopy,
   425→
   426→        (true, false, 0) => copy_debug.sparse_detection = SparseDebug::SeekHole,
   427→        (true, true, _) => copy_debug.sparse_detection = SparseDebug::SeekHoleZeros,
   428→
   429→        (true, false, _) => copy_debug.sparse_detection = SparseDebug::SeekHole,
   430→
   431→        (_, _, _) => (),
   432→    }
   433→    if check_dest_is_fifo(dest) {
   434→        copy_method = CopyMethod::FSCopy;
   435→    }
   436→    Ok((copy_debug, copy_method))
   437→}
   438→
   439→/// Handles debug results when flags are "--reflink=auto" and "--sparse=auto" and specifies what
   440→/// type of copy should be used
   441→fn handle_reflink_never_sparse_never(source: &Path) -> Result<CopyDebug, std::io::Error> {
   442→    let mut copy_debug = CopyDebug {
   443→        offload: OffloadReflinkDebug::Unknown,
   444→        reflink: OffloadReflinkDebug::No,
   445→        sparse_detection: SparseDebug::No,
   446→    };
   447→    let (data_flag, size, _blocks) = check_for_data(source)?;
   448→    let sparse_flag = check_sparse_detection(source)?;
   449→
   450→    if sparse_flag {
   451→        copy_debug.sparse_detection = SparseDebug::SeekHole;
   452→    }
   453→
   454→    if data_flag || size < 512 {
   455→        copy_debug.offload = OffloadReflinkDebug::Avoided;
   456→    }
   457→    Ok(copy_debug)
   458→}
   459→
   460→/// Handles debug results when flags are "--reflink=auto" and "--sparse=never", files will be copied
   461→/// through cloning them with fallback switching to [`std::fs::copy`]
   462→fn handle_reflink_auto_sparse_never(source: &Path) -> Result<CopyDebug, std::io::Error> {
   463→    let mut copy_debug = CopyDebug {
   464→        offload: OffloadReflinkDebug::Unknown,
   465→        reflink: OffloadReflinkDebug::No,
   466→        sparse_detection: SparseDebug::No,
   467→    };
   468→
   469→    let (data_flag, size, _blocks) = check_for_data(source)?;
   470→    let sparse_flag = check_sparse_detection(source)?;
   471→
   472→    if sparse_flag {
   473→        copy_debug.sparse_detection = SparseDebug::SeekHole;
   474→    }
   475→
   476→    if data_flag || size < 512 {
   477→        copy_debug.offload = OffloadReflinkDebug::Avoided;
   478→    }
   479→    Ok(copy_debug)
   480→}
   481→
   482→/// Handles debug results when flags are "--reflink=auto" and "--sparse=auto" and specifies what
   483→/// type of copy should be used
   484→fn handle_reflink_auto_sparse_auto(
   485→    source: &Path,
   486→    dest: &Path,
   487→) -> Result<(CopyDebug, CopyMethod), std::io::Error> {
   488→    let mut copy_debug = CopyDebug {
   489→        offload: OffloadReflinkDebug::Unknown,
   490→        reflink: OffloadReflinkDebug::Unsupported,
   491→        sparse_detection: SparseDebug::No,
   492→    };
   493→
   494→    let mut copy_method = CopyMethod::Default;
   495→    let (data_flag, size, blocks) = check_for_data(source)?;
   496→    let sparse_flag = check_sparse_detection(source)?;
   497→
   498→    if (data_flag && size != 0) || (size > 0 && size < 512) {
   499→        copy_debug.offload = OffloadReflinkDebug::Yes;
   500→    }
   501→
   502→    if data_flag && size == 0 {
   503→        // Handling /proc/ files
   504→        copy_debug.offload = OffloadReflinkDebug::Unsupported;
   505→    }
   506→    if sparse_flag {
   507→        if blocks == 0 && data_flag {
   508→            // Handling other "virtual" files
   509→            copy_debug.offload = OffloadReflinkDebug::Unsupported;
   510→
   511→            copy_method = CopyMethod::FSCopy; // Doing a standard copy for the virtual files
   512→        } else {
   513→            copy_method = CopyMethod::SparseCopyWithoutHole;
   514→        } // Since sparse_flag is true, sparse_detection shall be SeekHole for any non virtual
   515→        // regular sparse file and the file will be sparsely copied
   516→        copy_debug.sparse_detection = SparseDebug::SeekHole;
   517→    }
   518→
   519→    if check_dest_is_fifo(dest) {
   520→        copy_method = CopyMethod::FSCopy;
   521→    }
   522→    Ok((copy_debug, copy_method))
